/**
 * Branch Manager — Online Booking / Request Form
 * Embeddable form for peekskilltree.com that creates requests in Branch Manager
 * Also generates a standalone booking page at /branchmanager/book
 */
var OnlineBooking = {
  BOOKING_URL: 'https://branchmanager.app/book.html',

  render: function() {
    var bookingUrl = OnlineBooking.BOOKING_URL;

    // Stats from requests with source = online/booking/book
    var allRequests = DB.requests.getAll();
    var onlineReqs = allRequests.filter(function(r) {
      var src = (r.source || '').toLowerCase();
      return src === 'online' || src === 'booking' || src === 'book' || src === 'website' || src === 'web';
    });
    var convertedToQuote = onlineReqs.filter(function(r) {
      return r.status === 'quoted' || r.status === 'converted';
    });
    var conversionRate = onlineReqs.length > 0 ? Math.round(convertedToQuote.length / onlineReqs.length * 100) : 0;

    // Recent 30 days
    var thirtyAgo = new Date(Date.now() - 30 * 86400000).toISOString();
    var recentOnline = onlineReqs.filter(function(r) { return r.createdAt && r.createdAt >= thirtyAgo; });

    var html = '<div class="section-header"><h2>Online Booking</h2>'
      + '<p style="color:var(--text-light);margin-top:4px;">Let clients submit requests directly from your website. All submissions automatically create a new Request in Branch Manager.</p></div>';

    // Stats bar
    html += '<div class="stat-grid">'
      + UI.statCard('Online Requests', onlineReqs.length.toString(), 'All time from web form', '', '', '')
      + UI.statCard('Last 30 Days', recentOnline.length.toString(), 'Recent web submissions', recentOnline.length > 0 ? 'up' : '', '', '')
      + UI.statCard('Converted', convertedToQuote.length.toString(), 'Turned into quotes', '', '', '')
      + UI.statCard('Conversion Rate', conversionRate + '%', 'Requests → quotes', conversionRate >= 50 ? 'up' : '', '', '')
      + '</div>';

    // Share / distribute section (3 cards in a row)
    html += '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:20px;">';

    // Copy link card
    html += '<div style="background:var(--white);border-radius:12px;padding:18px;border:1px solid var(--border);display:flex;flex-direction:column;gap:10px;">'
      + '<h3 style="font-size:14px;margin:0;">🔗 Direct Link</h3>'
      + '<p style="font-size:12px;color:var(--text-light);margin:0;">Share with clients via text or email</p>'
      + '<div style="display:flex;gap:6px;">'
      + '<input type="text" value="' + bookingUrl + '" readonly onclick="this.select()" style="flex:1;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:11px;background:var(--bg);">'
      + '<button onclick="navigator.clipboard.writeText(\'' + bookingUrl + '\').then(function(){UI.toast(\'Link copied!\');})" style="background:var(--green-dark);color:#fff;border:none;padding:8px 12px;border-radius:6px;font-weight:600;cursor:pointer;font-size:12px;white-space:nowrap;">Copy</button>'
      + '</div>'
      + '<div style="display:flex;gap:6px;flex-wrap:wrap;">'
      + '<a href="sms:?body=' + encodeURIComponent('Request a free tree service estimate: ' + bookingUrl) + '" style="flex:1;text-align:center;background:#e8f5e9;color:var(--green-dark);border:none;padding:8px;border-radius:6px;font-size:12px;font-weight:600;text-decoration:none;">📱 Text</a>'
      + '<a href="mailto:?subject=' + encodeURIComponent('Request a Free Tree Estimate') + '&body=' + encodeURIComponent('You can request a free estimate here: ' + bookingUrl) + '" style="flex:1;text-align:center;background:#e3f2fd;color:#1565c0;border:none;padding:8px;border-radius:6px;font-size:12px;font-weight:600;text-decoration:none;">📧 Email</a>'
      + '</div></div>';

    // QR Code card
    var qrApiUrl = 'https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=' + encodeURIComponent(bookingUrl);
    html += '<div style="background:var(--white);border-radius:12px;padding:18px;border:1px solid var(--border);display:flex;flex-direction:column;align-items:center;gap:10px;">'
      + '<h3 style="font-size:14px;margin:0;">📱 QR Code</h3>'
      + '<p style="font-size:12px;color:var(--text-light);margin:0;text-align:center;">Print on business cards, job site signs</p>'
      + '<img src="' + qrApiUrl + '" alt="QR Code" style="width:120px;height:120px;border-radius:8px;border:1px solid var(--border);" onerror="this.style.display=\'none\'">'
      + '<a href="' + qrApiUrl + '" download="booking-qr.png" style="background:var(--green-dark);color:#fff;border:none;padding:8px 16px;border-radius:6px;font-weight:600;font-size:12px;text-decoration:none;text-align:center;">⬇ Download QR</a>'
      + '</div>';

    // Embed code card
    var embedCode = '<iframe src="' + bookingUrl + '" width="100%" height="600" frameborder="0" style="border-radius:12px;border:1px solid #e0e0e0;"></iframe>';
    html += '<div style="background:var(--white);border-radius:12px;padding:18px;border:1px solid var(--border);display:flex;flex-direction:column;gap:10px;">'
      + '<h3 style="font-size:14px;margin:0;">🖥 Website Embed</h3>'
      + '<p style="font-size:12px;color:var(--text-light);margin:0;">Paste on any page of peekskilltree.com</p>'
      + '<div style="background:#1d1d1f;border-radius:8px;padding:12px;overflow-x:auto;">'
      + '<code style="color:#4caf50;font-size:10px;white-space:pre;">&lt;iframe src="' + bookingUrl + '"\n  width="100%" height="600"\n  frameborder="0"&gt;\n&lt;/iframe&gt;</code>'
      + '</div>'
      + '<button onclick="navigator.clipboard.writeText(\'' + embedCode.replace(/'/g, "\\'") + '\').then(function(){UI.toast(\'Embed code copied!\');})" style="background:var(--green-dark);color:#fff;border:none;padding:8px 16px;border-radius:6px;font-weight:600;cursor:pointer;font-size:12px;">📋 Copy Embed Code</button>'
      + '</div>';

    html += '</div>'; // end 3-col grid

    // Form Settings
    html += '<div style="background:var(--white);border-radius:12px;padding:20px;border:1px solid var(--border);margin-bottom:16px;">'
      + '<h3 style="font-size:15px;margin-bottom:12px;">Form Settings</h3>'
      + '<div style="display:grid;gap:12px;">';

    var services = [
      'Tree Removal', 'Tree Pruning', 'Stump Removal', 'Storm Damage',
      'Land Clearing', 'Bucket Truck Work', 'Cabling & Bracing',
      'Tree Health Assessment', 'Firewood', 'Other'
    ];
    var savedServices = localStorage.getItem('bm-booking-services') || services.join(',');
    html += '<div><label style="font-size:12px;color:var(--text-light);display:block;margin-bottom:6px;font-weight:600;">Services shown on form</label>'
      + '<div style="display:flex;flex-wrap:wrap;gap:6px;">';
    services.forEach(function(s) {
      var checked = savedServices.includes(s);
      html += '<label style="display:flex;align-items:center;gap:4px;font-size:13px;padding:6px 10px;background:' + (checked ? '#e8f5e9' : 'var(--bg)') + ';border-radius:6px;cursor:pointer;border:1px solid ' + (checked ? '#c8e6c9' : 'var(--border)') + ';">'
        + '<input type="checkbox" ' + (checked ? 'checked' : '') + ' onchange="OnlineBooking.toggleService(\'' + s + '\')" style="width:14px;height:14px;">'
        + s + '</label>';
    });
    html += '</div></div>';

    html += '<div><label style="font-size:12px;color:var(--text-light);display:block;margin-bottom:4px;font-weight:600;">Auto-reply message (sent after form submission)</label>'
      + '<textarea id="booking-autoreply" rows="3" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:14px;font-family:inherit;">'
      + (localStorage.getItem('bm-booking-autoreply') || "Thanks for your request! We'll review it and get back to you within 2 hours during business hours. — Doug, " + (CompanyInfo.get('name')))
      + '</textarea>'
      + '<button onclick="localStorage.setItem(\'bm-booking-autoreply\',document.getElementById(\'booking-autoreply\').value);UI.toast(\'Auto-reply saved!\')" style="background:var(--green-dark);color:#fff;border:none;padding:6px 14px;border-radius:6px;font-weight:600;cursor:pointer;font-size:12px;margin-top:6px;">Save Message</button>'
      + '</div></div></div>';

    // Recent online requests
    if (onlineReqs.length > 0) {
      var sortedOnline = onlineReqs.slice().sort(function(a, b) {
        return new Date(b.createdAt) - new Date(a.createdAt);
      });
      html += '<div style="background:var(--white);border-radius:12px;padding:20px;border:1px solid var(--border);margin-bottom:16px;">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">'
        + '<h3 style="font-size:15px;margin:0;">Recent Online Submissions</h3>'
        + '<button onclick="loadPage(\'requests\')" style="background:none;border:1px solid var(--border);padding:5px 12px;border-radius:6px;font-size:12px;cursor:pointer;color:var(--accent);">View All Requests →</button>'
        + '</div>'
        + '<table class="data-table"><thead><tr><th>Client</th><th>Property</th><th>Service</th><th>Status</th><th>Date</th></tr></thead><tbody>';
      sortedOnline.slice(0, 10).forEach(function(r) {
        html += '<tr onclick="RequestsPage.showDetail(\'' + r.id + '\')" style="cursor:pointer;">'
          + '<td><strong>' + UI.esc(r.clientName || '—') + '</strong></td>'
          + '<td style="color:var(--text-light);font-size:12px;">' + UI.esc((r.property || '').substr(0, 30)) + '</td>'
          + '<td style="font-size:12px;">' + UI.esc(r.serviceType || r.notes || '—') + '</td>'
          + '<td>' + UI.statusBadge(r.status) + '</td>'
          + '<td style="font-size:12px;color:var(--text-light);">' + UI.dateShort(r.createdAt) + '</td>'
          + '</tr>';
      });
      html += '</tbody></table></div>';
    }

    // Live preview
    html += '<div style="background:var(--white);border-radius:12px;padding:20px;border:1px solid var(--border);">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">'
      + '<h3 style="font-size:15px;margin:0;">Form Preview</h3>'
      + '<a href="' + bookingUrl + '" target="_blank" rel="noopener noreferrer" style="background:var(--green-dark);color:#fff;border:none;padding:6px 14px;border-radius:6px;font-weight:600;font-size:12px;text-decoration:none;">Open Full Form ↗</a>'
      + '</div>'
      + '<div style="border:2px solid var(--border);border-radius:12px;padding:24px;max-width:500px;margin:0 auto;">'
      + OnlineBooking._renderFormPreview()
      + '</div></div>';

    return html;
  },

  _renderFormPreview: function() {
    return '<div style="text-align:center;margin-bottom:20px;">'
      + '<div style="font-size:24px;">🌳</div>'
      + '<h3 style="font-size:18px;color:#1a3c12;">Request a Free Estimate</h3>'
      + '<p style="font-size:13px;color:#666;">' + (CompanyInfo.get('name')) + ' — Peekskill, NY</p></div>'
      + '<div style="display:grid;gap:10px;">'
      + '<input type="text" placeholder="Your Name *" style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;" disabled>'
      + '<input type="tel" placeholder="Phone Number *" style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;" disabled>'
      + '<input type="email" placeholder="Email" style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;" disabled>'
      + '<input type="text" placeholder="Property Address *" style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;" disabled>'
      + '<select style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;color:#666;" disabled>'
      + '<option>Select Service Needed...</option>'
      + '<option>Tree Removal</option><option>Tree Pruning</option><option>Stump Removal</option>'
      + '</select>'
      + '<textarea placeholder="Describe the work needed..." rows="3" style="padding:12px;border:2px solid #e0e0e0;border-radius:8px;font-size:15px;font-family:inherit;resize:vertical;" disabled></textarea>'
      + '<button style="background:#1a3c12;color:#fff;border:none;padding:14px;border-radius:8px;font-size:16px;font-weight:700;cursor:not-allowed;opacity:.8;">Submit Request</button>'
      + '<p style="font-size:11px;color:#999;text-align:center;margin:0;">Preview only — <a href="' + OnlineBooking.BOOKING_URL + '" target="_blank" rel="noopener noreferrer" style="color:#1a3c12;">open live form</a></p>'
      + '</div>';
  },

  toggleService: function(service) {
    var current = (localStorage.getItem('bm-booking-services') || '').split(',');
    var idx = current.indexOf(service);
    if (idx >= 0) current.splice(idx, 1);
    else current.push(service);
    localStorage.setItem('bm-booking-services', current.filter(Boolean).join(','));
  },

  _copyEmbed: function() {
    var code = '<iframe src="' + OnlineBooking.BOOKING_URL + '" width="100%" height="600" frameborder="0" style="border-radius:12px;border:1px solid #e0e0e0;"></iframe>';
    navigator.clipboard.writeText(code).then(function() { UI.toast('Copied!'); });
  }
};

;
/* ──── src/pages/formbuilder.js ──── */
/**
 * Branch Manager — Form Builder v1
 * No-code editor for the online booking form (book.html)
 * Config stored in Supabase settings table + localStorage
 */
var FormBuilderPage = {

  _STORAGE_KEY: 'bm-form-config',
  _SUPABASE_URL: 'https://ltpivkqahvplapyagljt.supabase.co',
  _SUPABASE_KEY: (typeof SupabaseDB !== 'undefined' && SupabaseDB.ANON_KEY) || '',

  _defaultConfig: function() {
    return {
      title: BM_CONFIG.companyName,
      subtitle: BM_CONFIG.city + ' — ' + BM_CONFIG.tagline,
      buttonText: 'Request Free Estimate',
      successTitle: 'Request Received!',
      successMessage: "Thanks! We'll review your request and get back to you within 2 hours during business hours.",
      notifyEmail: BM_CONFIG.email,
      fields: [
        { id: 'f1', label: 'Your Name', type: 'text', placeholder: 'First and last name', required: true },
        { id: 'f2', label: 'Phone Number', type: 'tel', placeholder: '(914) 555-1234', required: true },
        { id: 'f3', label: 'Email', type: 'email', placeholder: 'you@email.com', required: false },
        { id: 'f4', label: 'Property Address', type: 'text', placeholder: '123 Main St, Peekskill, NY', required: true },
        { id: 'f5', label: 'Service Needed', type: 'select', required: true, options: [
          'Tree Removal', 'Tree Pruning / Trimming', 'Stump Removal',
          'Storm Damage / Emergency', 'Land Clearing', 'Bucket Truck Work',
          'Cabling & Bracing', 'Tree Health Assessment', 'Gutter Clean Out',
          'Firewood', 'Other'
        ]},
        { id: 'f6', label: 'Describe the Work', type: 'textarea', placeholder: 'Tell us about the trees, the situation, any concerns...', required: false }
      ]
    };
  },

  _getConfig: function() {
    try {
      var saved = JSON.parse(localStorage.getItem(FormBuilderPage._STORAGE_KEY));
      return saved || FormBuilderPage._defaultConfig();
    } catch(e) { return FormBuilderPage._defaultConfig(); }
  },

  _saveConfig: function(cfg) {
    localStorage.setItem(FormBuilderPage._STORAGE_KEY, JSON.stringify(cfg));
  },

  render: function() {
    var cfg = FormBuilderPage._getConfig();
    var html = '<div style="max-width:900px;margin:0 auto;">';

    // Header
    html += '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:20px;flex-wrap:wrap;gap:12px;">'
      + '<div>'
      + '<h2 style="margin:0;font-size:20px;">📋 Online Booking Form Editor</h2>'
      + '<p style="margin:4px 0 0;font-size:13px;color:var(--text-light);">Edit the form on peekskilltree.com/contact.html — no coding needed</p>'
      + '</div>'
      + '<div style="display:flex;gap:8px;">'
      + '<button class="btn btn-outline" onclick="FormBuilderPage.preview()" style="font-size:13px;">👁 Preview Form</button>'
      + '<button class="btn btn-primary" onclick="FormBuilderPage.save()" id="fb-save-btn" style="font-size:13px;">💾 Save & Publish</button>'
      + '</div>'
      + '</div>';

    // Two-column layout
    html += '<div style="display:grid;grid-template-columns:1fr 380px;gap:20px;align-items:start;">';

    // LEFT: Form fields editor
    html += '<div>';
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:20px;margin-bottom:16px;">'
      + '<h3 style="font-size:15px;font-weight:700;margin:0 0 16px;">Form Fields</h3>'
      + '<div id="fb-fields">';

    cfg.fields.forEach(function(f, i) {
      html += FormBuilderPage._renderFieldRow(f, i, cfg.fields.length);
    });

    html += '</div>'
      + '<button class="btn btn-outline" onclick="FormBuilderPage.addField()" style="width:100%;margin-top:12px;font-size:13px;">+ Add Field</button>'
      + '</div>';

    // Service options editor (only shown if select field exists)
    var selectField = cfg.fields.find(function(f){ return f.type === 'select'; });
    if (selectField) {
      html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:20px;margin-bottom:16px;">'
        + '<h3 style="font-size:15px;font-weight:700;margin:0 0 4px;">Service Options</h3>'
        + '<p style="font-size:12px;color:var(--text-light);margin:0 0 12px;">Edit the dropdown choices — one per line</p>'
        + '<textarea id="fb-options" style="width:100%;height:180px;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:13px;font-family:inherit;resize:vertical;" onchange="FormBuilderPage._saveOptions()">'
        + (selectField.options || []).join('\n')
        + '</textarea>'
        + '</div>';
    }
    html += '</div>';

    // RIGHT: Settings panel + live preview
    html += '<div>';

    // Form settings
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:20px;margin-bottom:16px;">'
      + '<h3 style="font-size:15px;font-weight:700;margin:0 0 16px;">Form Settings</h3>'
      + '<div style="margin-bottom:12px;">'
      + '<label style="font-size:12px;font-weight:600;color:var(--text-light);display:block;margin-bottom:4px;">FORM TITLE</label>'
      + '<input id="fb-title" type="text" value="' + UI.esc(cfg.title) + '" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;" onchange="FormBuilderPage._liveUpdate()">'
      + '</div>'
      + '<div style="margin-bottom:12px;">'
      + '<label style="font-size:12px;font-weight:600;color:var(--text-light);display:block;margin-bottom:4px;">SUBTITLE</label>'
      + '<input id="fb-subtitle" type="text" value="' + UI.esc(cfg.subtitle) + '" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + '</div>'
      + '<div style="margin-bottom:12px;">'
      + '<label style="font-size:12px;font-weight:600;color:var(--text-light);display:block;margin-bottom:4px;">BUTTON TEXT</label>'
      + '<input id="fb-btn-text" type="text" value="' + UI.esc(cfg.buttonText) + '" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + '</div>'
      + '<div style="margin-bottom:12px;">'
      + '<label style="font-size:12px;font-weight:600;color:var(--text-light);display:block;margin-bottom:4px;">SUCCESS MESSAGE</label>'
      + '<textarea id="fb-success-msg" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:13px;font-family:inherit;resize:vertical;height:70px;">' + UI.esc(cfg.successMessage) + '</textarea>'
      + '</div>'
      + '<div>'
      + '<label style="font-size:12px;font-weight:600;color:var(--text-light);display:block;margin-bottom:4px;">NOTIFY EMAIL</label>'
      + '<input id="fb-notify-email" type="email" value="' + UI.esc(cfg.notifyEmail) + '" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + '</div>'
      + '</div>';

    // Mini live preview
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:20px;">'
      + '<h3 style="font-size:15px;font-weight:700;margin:0 0 12px;">Live Preview</h3>'
      + '<div id="fb-preview" style="border:2px solid var(--border);border-radius:10px;padding:16px;background:#f9fafb;">'
      + FormBuilderPage._buildPreview(cfg)
      + '</div>'
      + '<p style="font-size:11px;color:var(--text-light);margin:8px 0 0;text-align:center;">Form live at <a href="https://peekskilltree.com/contact.html" target="_blank" rel="noopener noreferrer">peekskilltree.com/contact.html</a></p>'
      + '</div>';

    html += '</div></div></div>';
    return html;
  },

  _renderFieldRow: function(f, idx, total) {
    var typeIcons = { text: '📝', tel: '📞', email: '📧', select: '▼', textarea: '📄' };
    var html = '<div id="fb-row-' + f.id + '" style="display:flex;align-items:center;gap:8px;padding:10px 12px;border:1px solid var(--border);border-radius:8px;margin-bottom:8px;background:var(--bg);">'
      // Drag handle
      + '<span style="cursor:grab;color:var(--text-light);font-size:16px;">⠿</span>'
      // Type icon
      + '<span style="font-size:14px;" title="' + f.type + '">' + (typeIcons[f.type] || '📝') + '</span>'
      // Label input
      + '<input type="text" value="' + UI.esc(f.label) + '" data-field-id="' + f.id + '" data-prop="label"'
      + ' style="flex:1;padding:6px 10px;border:2px solid var(--border);border-radius:6px;font-size:13px;"'
      + ' onchange="FormBuilderPage._updateField(this)">'
      // Type select
      + '<select data-field-id="' + f.id + '" data-prop="type" onchange="FormBuilderPage._updateField(this);loadPage(\'formbuilder\')"'
      + ' style="padding:6px;border:2px solid var(--border);border-radius:6px;font-size:12px;">'
      + ['text','tel','email','select','textarea'].map(function(t){ return '<option value="'+t+'"'+(f.type===t?' selected':'')+'>'+t+'</option>'; }).join('')
      + '</select>'
      // Required toggle
      + '<label style="display:flex;align-items:center;gap:4px;font-size:12px;color:var(--text-light);white-space:nowrap;cursor:pointer;">'
      + '<input type="checkbox" data-field-id="' + f.id + '" data-prop="required" onchange="FormBuilderPage._updateField(this)"'
      + (f.required ? ' checked' : '') + ' style="cursor:pointer;">'
      + 'Req</label>'
      // Move up/down
      + '<div style="display:flex;flex-direction:column;gap:2px;">'
      + (idx > 0 ? '<button onclick="FormBuilderPage.moveField(\'' + f.id + '\',-1)" style="background:none;border:none;cursor:pointer;padding:1px;font-size:10px;line-height:1;" title="Move up">▲</button>' : '<span style="width:16px;"></span>')
      + (idx < total - 1 ? '<button onclick="FormBuilderPage.moveField(\'' + f.id + '\',1)" style="background:none;border:none;cursor:pointer;padding:1px;font-size:10px;line-height:1;" title="Move down">▼</button>' : '<span style="width:16px;"></span>')
      + '</div>'
      // Delete
      + (total > 1 ? '<button onclick="FormBuilderPage.removeField(\'' + f.id + '\')" style="background:none;border:none;cursor:pointer;color:#dc3545;font-size:16px;padding:2px 4px;" title="Remove">✕</button>' : '')
      + '</div>';
    return html;
  },

  _buildPreview: function(cfg) {
    var html = '<div style="font-size:13px;">'
      + '<div style="text-align:center;margin-bottom:12px;">'
      + '<div style="font-size:20px;">🌳</div>'
      + '<div style="font-weight:700;color:#1a3c12;font-size:14px;">' + UI.esc(cfg.title) + '</div>'
      + '<div style="font-size:11px;color:#888;">' + UI.esc(cfg.subtitle) + '</div>'
      + '</div>';
    cfg.fields.slice(0, 4).forEach(function(f) {
      html += '<div style="margin-bottom:8px;">'
        + '<label style="font-size:11px;font-weight:600;color:#555;display:block;margin-bottom:2px;">'
        + UI.esc(f.label) + (f.required ? ' *' : '')
        + '</label>';
      if (f.type === 'textarea') {
        html += '<div style="height:36px;border:2px solid #e0e0e0;border-radius:6px;background:#fafafa;"></div>';
      } else if (f.type === 'select') {
        html += '<div style="height:28px;border:2px solid #e0e0e0;border-radius:6px;background:#fafafa;padding:4px 8px;font-size:11px;color:#aaa;">'
          + (f.options && f.options[0] ? UI.esc(f.options[0]) : 'Select...') + '</div>';
      } else {
        html += '<div style="height:28px;border:2px solid #e0e0e0;border-radius:6px;background:#fafafa;padding:4px 8px;font-size:11px;color:#aaa;">'
          + UI.esc(f.placeholder || '') + '</div>';
      }
      html += '</div>';
    });
    if (cfg.fields.length > 4) {
      html += '<div style="font-size:11px;color:#999;text-align:center;margin:4px 0;">+ ' + (cfg.fields.length - 4) + ' more field(s)</div>';
    }
    html += '<div style="background:#1a3c12;color:#fff;text-align:center;padding:8px;border-radius:8px;font-size:12px;font-weight:700;margin-top:8px;">'
      + UI.esc(cfg.buttonText) + '</div>'
      + '</div>';
    return html;
  },

  _updateField: function(el) {
    var cfg = FormBuilderPage._getConfig();
    var id = el.dataset.fieldId;
    var prop = el.dataset.prop;
    var field = cfg.fields.find(function(f){ return f.id === id; });
    if (!field) return;
    if (prop === 'required') field[prop] = el.checked;
    else field[prop] = el.value;
    FormBuilderPage._saveConfig(cfg);
    // Update preview
    var prev = document.getElementById('fb-preview');
    if (prev) prev.innerHTML = FormBuilderPage._buildPreview(cfg);
  },

  _saveOptions: function() {
    var cfg = FormBuilderPage._getConfig();
    var textarea = document.getElementById('fb-options');
    if (!textarea) return;
    var selectField = cfg.fields.find(function(f){ return f.type === 'select'; });
    if (selectField) {
      selectField.options = textarea.value.split('\n').map(function(s){ return s.trim(); }).filter(Boolean);
      FormBuilderPage._saveConfig(cfg);
    }
  },

  _liveUpdate: function() {
    var cfg = FormBuilderPage._getConfig();
    var titleEl = document.getElementById('fb-title');
    if (titleEl) cfg.title = titleEl.value;
    FormBuilderPage._saveConfig(cfg);
    var prev = document.getElementById('fb-preview');
    if (prev) prev.innerHTML = FormBuilderPage._buildPreview(cfg);
  },

  addField: function() {
    var cfg = FormBuilderPage._getConfig();
    cfg.fields.push({
      id: 'f' + Date.now(),
      label: 'New Field',
      type: 'text',
      placeholder: '',
      required: false
    });
    FormBuilderPage._saveConfig(cfg);
    loadPage('formbuilder');
  },

  removeField: function(id) {
    var cfg = FormBuilderPage._getConfig();
    cfg.fields = cfg.fields.filter(function(f){ return f.id !== id; });
    FormBuilderPage._saveConfig(cfg);
    loadPage('formbuilder');
  },

  moveField: function(id, dir) {
    var cfg = FormBuilderPage._getConfig();
    var idx = cfg.fields.findIndex(function(f){ return f.id === id; });
    if (idx < 0) return;
    var newIdx = idx + dir;
    if (newIdx < 0 || newIdx >= cfg.fields.length) return;
    var tmp = cfg.fields[idx];
    cfg.fields[idx] = cfg.fields[newIdx];
    cfg.fields[newIdx] = tmp;
    FormBuilderPage._saveConfig(cfg);
    loadPage('formbuilder');
  },

  save: function() {
    // Collect all current values from DOM before saving
    var cfg = FormBuilderPage._getConfig();
    var get = function(id){ var el = document.getElementById(id); return el ? el.value : null; };
    cfg.title = get('fb-title') || cfg.title;
    cfg.subtitle = get('fb-subtitle') || cfg.subtitle;
    cfg.buttonText = get('fb-btn-text') || cfg.buttonText;
    cfg.successMessage = get('fb-success-msg') || cfg.successMessage;
    cfg.notifyEmail = get('fb-notify-email') || cfg.notifyEmail;

    // Save options if any
    var optEl = document.getElementById('fb-options');
    if (optEl) {
      var sf = cfg.fields.find(function(f){ return f.type === 'select'; });
      if (sf) sf.options = optEl.value.split('\n').map(function(s){ return s.trim(); }).filter(Boolean);
    }

    FormBuilderPage._saveConfig(cfg);

    // Push to Supabase settings table
    var btn = document.getElementById('fb-save-btn');
    if (btn) { btn.textContent = '⏳ Publishing...'; btn.disabled = true; }

    fetch(FormBuilderPage._SUPABASE_URL + '/rest/v1/settings', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'apikey': FormBuilderPage._SUPABASE_KEY,
        'Authorization': 'Bearer ' + FormBuilderPage._SUPABASE_KEY,
        'Prefer': 'resolution=merge-duplicates'
      },
      body: JSON.stringify({ key: 'form_config', value: JSON.stringify(cfg) })
    })
    .then(function(r) {
      if (btn) { btn.textContent = '✅ Published!'; btn.disabled = false; setTimeout(function(){ if(btn) btn.textContent = '💾 Save & Publish'; }, 2000); }
      UI.toast('✅ Form saved — live at peekskilltree.com/contact.html');
    })
    .catch(function() {
      if (btn) { btn.textContent = '💾 Save & Publish'; btn.disabled = false; }
      UI.toast('⚠️ Saved locally — Supabase sync failed');
    });
  },

  preview: function() {
    window.open('https://branchmanager.app/book.html', '_blank');
  }
};

;
/* ──── src/pages/receptionist.js ──── */
/**
 * Branch Manager — Receptionist v2
 * Dialpad integration hub: call log, SMS inbox, voicemail, settings
 * Mirrors Jobber's communication features through Dialpad
 */
var Receptionist = {
  _tab: 'calls',
  _connected: false,

  render: function() {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    Receptionist._connected = !!settings.connected;
    var calls = DB.getAll('bm-call-log');
    var sms = DB.getAll('bm-sms-inbox');
    var voicemails = DB.getAll('bm-voicemails');
    var missed = calls.filter(function(c) { return c.type === 'missed'; });

    var html = '<div style="max-width:1000px;margin:0 auto;">';

    // Stat cards
    html += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:20px;">';
    html += Receptionist._stat('Total Calls', calls.length, '📞');
    html += Receptionist._stat('Missed Calls', missed.length, '📵', missed.length > 0 ? '#dc3545' : null);
    html += Receptionist._stat('SMS Messages', sms.length, '💬');
    html += Receptionist._stat('Voicemails', voicemails.filter(function(v){return !v.read;}).length + ' unread', '🎙️');
    html += '</div>';

    // Connection status
    if (!Receptionist._connected) {
      html += '<div style="background:#fef3c7;border:2px solid #f59e0b;border-radius:12px;padding:24px;margin-bottom:20px;display:flex;align-items:center;gap:20px;">'
        + '<div style="font-size:40px;">🔌</div>'
        + '<div style="flex:1;">'
        + '<h3 style="margin:0 0 6px;font-size:16px;color:#92400e;">Connect Your Phone System</h3>'
        + '<p style="margin:0;font-size:13px;color:#78350f;">Connect Dialpad to log calls, receive SMS, and get voicemail transcriptions automatically.</p>'
        + '</div>'
        + '<button class="btn btn-primary" onclick="Receptionist.showConnect()">Connect Dialpad</button>'
        + '</div>';
    } else {
      html += '<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:12px;padding:16px;margin-bottom:20px;display:flex;align-items:center;gap:16px;">'
        + '<div style="width:10px;height:10px;background:#16a34a;border-radius:50%;"></div>'
        + '<div style="flex:1;font-size:13px;color:#166534;"><strong>Dialpad connected</strong> — ' + (settings.phoneNumber || 'Business line') + '</div>'
        + '<button class="btn btn-outline" style="font-size:12px;" onclick="Receptionist.disconnect()">Disconnect</button>'
        + '</div>';
    }

    // Tabs
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;overflow:hidden;">';
    html += '<div style="display:flex;border-bottom:1px solid var(--border);">';
    var tabs = [['calls','Call Log','📞'],['sms','SMS Inbox','💬'],['voicemail','Voicemail','🎙️'],['settings','Settings','⚙️']];
    tabs.forEach(function(t) {
      var active = Receptionist._tab === t[0];
      html += '<button style="flex:1;padding:14px;border:none;background:' + (active ? 'var(--white)' : 'var(--bg)') + ';cursor:pointer;font-size:13px;font-weight:' + (active ? '700' : '500') + ';color:' + (active ? 'var(--accent)' : 'var(--text-light)') + ';border-bottom:2px solid ' + (active ? 'var(--accent)' : 'transparent') + ';" '
        + 'onclick="Receptionist._tab=\'' + t[0] + '\';App.render()">' + t[2] + ' ' + t[1] + '</button>';
    });
    html += '</div>';

    html += '<div style="padding:20px;">';
    if (Receptionist._tab === 'calls') html += Receptionist._renderCalls(calls);
    else if (Receptionist._tab === 'sms') html += Receptionist._renderSMS(sms);
    else if (Receptionist._tab === 'voicemail') html += Receptionist._renderVoicemail(voicemails);
    else html += Receptionist._renderSettings(settings);
    html += '</div></div></div>';
    return html;
  },

  _stat: function(label, value, icon, color) {
    return '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:18px;text-align:center;">'
      + '<div style="font-size:24px;margin-bottom:4px;">' + icon + '</div>'
      + '<div style="font-size:22px;font-weight:800;' + (color ? 'color:'+color : '') + ';">' + value + '</div>'
      + '<div style="font-size:11px;color:var(--text-light);text-transform:uppercase;letter-spacing:.5px;">' + label + '</div>'
      + '</div>';
  },

  _renderCalls: function(calls) {
    var html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">';
    html += '<span style="font-size:14px;font-weight:700;">' + calls.length + ' calls</span>';
    html += '<button class="btn btn-primary" style="font-size:12px;" onclick="Receptionist.logCall()">+ Log Call</button>';
    html += '</div>';

    if (calls.length === 0) {
      return html + '<div style="text-align:center;padding:40px;color:var(--text-light);">'
        + '<div style="font-size:48px;margin-bottom:12px;">📞</div>'
        + '<h3>No calls logged yet</h3><p>Calls will appear here when Dialpad is connected, or log them manually.</p></div>';
    }

    html += '<table class="data-table" style="width:100%;"><thead><tr>'
      + '<th>DATE</th><th>CALLER</th><th>PHONE</th><th>DURATION</th><th>TYPE</th><th>CLIENT</th><th></th>'
      + '</tr></thead><tbody>';
    calls.sort(function(a,b){return new Date(b.date)-new Date(a.date);}).forEach(function(c) {
      var typeColors = { inbound:'#16a34a', outbound:'#2563eb', missed:'#dc3545' };
      html += '<tr>'
        + '<td>' + new Date(c.date).toLocaleString() + '</td>'
        + '<td style="font-weight:600;">' + UI.esc(c.callerName || 'Unknown') + '</td>'
        + '<td>' + UI.esc(c.phone || '—') + '</td>'
        + '<td>' + (c.duration || '—') + '</td>'
        + '<td><span style="color:' + (typeColors[c.type] || '#6b7280') + ';font-weight:600;font-size:12px;">' + (c.type || 'inbound') + '</span></td>'
        + '<td>' + UI.esc(c.linkedClient || '—') + '</td>'
        + '<td><button class="btn btn-outline" style="font-size:11px;padding:2px 6px;" onclick="Receptionist.removeCall(\'' + c.id + '\')">×</button></td>'
        + '</tr>';
    });
    html += '</tbody></table>';
    return html;
  },

  _renderSMS: function(sms) {
    var html = '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px;">';
    html += '<span style="font-size:14px;font-weight:700;">' + sms.length + ' messages</span>';
    html += '<button class="btn btn-primary" style="font-size:12px;" onclick="Receptionist.composeSMS()">+ New SMS</button>';
    html += '</div>';

    if (sms.length === 0) {
      return html + '<div style="text-align:center;padding:40px;color:var(--text-light);">'
        + '<div style="font-size:48px;margin-bottom:12px;">💬</div>'
        + '<h3>No SMS messages</h3><p>Messages will appear here when Dialpad is connected.</p></div>';
    }

    sms.sort(function(a,b){return new Date(b.date)-new Date(a.date);}).forEach(function(m) {
      var unread = !m.read;
      html += '<div style="padding:14px;border-bottom:1px solid var(--border);cursor:pointer;background:' + (unread ? '#f0fdf4' : 'transparent') + ';" '
        + 'onclick="Receptionist.viewSMS(\'' + m.id + '\')">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;">'
        + '<div style="font-weight:' + (unread ? '700' : '500') + ';font-size:14px;">' + UI.esc(m.from || 'Unknown') + (unread ? ' <span style="background:#16a34a;color:#fff;font-size:9px;padding:1px 6px;border-radius:8px;">NEW</span>' : '') + '</div>'
        + '<div style="font-size:11px;color:var(--text-light);">' + new Date(m.date).toLocaleString() + '</div>'
        + '</div>'
        + '<div style="font-size:13px;color:var(--text-light);margin-top:4px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">' + UI.esc(m.message || '') + '</div>'
        + '</div>';
    });
    return html;
  },

  _renderVoicemail: function(voicemails) {
    var html = '<div style="margin-bottom:16px;font-size:14px;font-weight:700;">' + voicemails.length + ' voicemails</div>';

    if (voicemails.length === 0) {
      return '<div style="text-align:center;padding:40px;color:var(--text-light);">'
        + '<div style="font-size:48px;margin-bottom:12px;">🎙️</div>'
        + '<h3>No voicemails</h3><p>Voicemails with AI transcription will appear here.</p></div>';
    }

    voicemails.sort(function(a,b){return new Date(b.date)-new Date(a.date);}).forEach(function(v) {
      html += '<div style="padding:16px;border:1px solid var(--border);border-radius:10px;margin-bottom:10px;background:' + (!v.read ? '#f0fdf4' : 'var(--white)') + ';">'
        + '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">'
        + '<div style="font-weight:700;font-size:14px;">' + UI.esc(v.callerName || v.phone || 'Unknown') + '</div>'
        + '<div style="font-size:11px;color:var(--text-light);">' + (v.duration || '0:30') + ' — ' + new Date(v.date).toLocaleString() + '</div>'
        + '</div>'
        + '<div style="background:var(--bg);border-radius:8px;padding:12px;font-size:13px;color:var(--text);line-height:1.5;">'
        + '<div style="font-size:10px;font-weight:700;color:var(--text-light);text-transform:uppercase;margin-bottom:4px;">AI Transcription</div>'
        + UI.esc(v.transcription || 'Transcription processing...')
        + '</div>'
        + '<div style="margin-top:8px;display:flex;gap:8px;">'
        + '<button class="btn btn-outline" style="font-size:11px;" onclick="Receptionist.callback(\'' + UI.esc(v.phone || '') + '\')">Call Back</button>'
        + '<button class="btn btn-outline" style="font-size:11px;" onclick="Receptionist.createRequest(\'' + UI.esc(v.callerName || '') + '\',\'' + UI.esc(v.phone || '') + '\')">Create Request</button>'
        + '</div></div>';
    });
    return html;
  },

  _renderSettings: function(settings) {
    var html = '<div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;">';

    // Provider selection
    html += '<div style="grid-column:1/-1;">';
    html += '<h4 style="margin:0 0 12px;font-size:14px;font-weight:700;">Phone Provider</h4>';
    html += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;">';
    var providers = [
      { name:'Dialpad', color:'#7C3AED', icon:'☎️', desc:'Business phone, SMS, voicemail, call recording' },
      { name:'OpenPhone', color:'#3B82F6', icon:'📱', desc:'Simple business phone with shared inbox' },
      { name:'Google Voice', color:'#34A853', icon:'🔊', desc:'Free business number with forwarding' },
      { name:'RingCentral', color:'#F97316', icon:'📡', desc:'Enterprise VoIP, SMS, fax & messaging' }
    ];
    providers.forEach(function(p) {
      var selected = settings.provider === p.name;
      html += '<div style="border:2px solid ' + (selected ? p.color : 'var(--border)') + ';border-radius:10px;padding:14px;cursor:pointer;text-align:center;" '
        + 'onclick="Receptionist.selectProvider(\'' + p.name + '\')">'
        + '<div style="font-size:24px;margin-bottom:6px;">' + p.icon + '</div>'
        + '<div style="font-weight:700;font-size:13px;">' + p.name + '</div>'
        + '<div style="font-size:11px;color:var(--text-light);margin-top:4px;">' + p.desc + '</div>'
        + (selected ? '<div style="margin-top:8px;font-size:11px;color:' + p.color + ';font-weight:700;">✓ Selected</div>' : '')
        + '</div>';
    });
    html += '</div></div>';

    // Auto-reply settings
    html += '<div>'
      + '<h4 style="margin:0 0 12px;font-size:14px;font-weight:700;">Auto-Reply</h4>'
      + '<label style="display:flex;align-items:center;gap:8px;margin-bottom:12px;cursor:pointer;">'
      + '<input type="checkbox" ' + (settings.autoReply ? 'checked' : '') + ' onchange="Receptionist.toggleSetting(\'autoReply\',this.checked)"> '
      + '<span style="font-size:13px;">Enable auto-reply for missed calls</span></label>'
      + '<textarea style="width:100%;min-height:80px;border:1px solid var(--border);border-radius:8px;padding:10px;font-size:13px;" '
      + 'placeholder="Thanks for calling ' + BM_CONFIG.companyName + '! We missed your call but will get back to you within 1 hour."'
      + ' onblur="Receptionist.saveSetting(\'autoReplyMsg\',this.value)">' + UI.esc(settings.autoReplyMsg || '') + '</textarea>'
      + '</div>';

    // Business hours
    html += '<div>'
      + '<h4 style="margin:0 0 12px;font-size:14px;font-weight:700;">Business Hours</h4>'
      + '<div style="display:grid;grid-template-columns:auto 1fr 1fr;gap:8px;align-items:center;">';
    var days = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
    var hours = settings.hours || {};
    days.forEach(function(d) {
      var h = hours[d] || { open:'8:00', close:'17:00', enabled: d !== 'Sun' };
      html += '<label style="font-size:13px;display:flex;align-items:center;gap:6px;">'
        + '<input type="checkbox" ' + (h.enabled ? 'checked' : '') + ' onchange="Receptionist.toggleDay(\'' + d + '\',this.checked)"> ' + d
        + '</label>'
        + '<input type="time" value="' + h.open + '" style="padding:4px;border:1px solid var(--border);border-radius:4px;font-size:12px;" onchange="Receptionist.setHour(\'' + d + '\',\'open\',this.value)">'
        + '<input type="time" value="' + h.close + '" style="padding:4px;border:1px solid var(--border);border-radius:4px;font-size:12px;" onchange="Receptionist.setHour(\'' + d + '\',\'close\',this.value)">';
    });
    html += '</div></div>';

    // Additional toggles
    html += '<div style="grid-column:1/-1;">'
      + '<h4 style="margin:0 0 12px;font-size:14px;font-weight:700;">Features</h4>'
      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;">';
    var features = [
      ['callRecording','Call Recording','Record all calls for quality & training'],
      ['voicemailTranscription','Voicemail Transcription','AI-powered voicemail to text'],
      ['missedCallAlerts','Missed Call Alerts','Get notified of every missed call'],
      ['autoCreateRequest','Auto-Create Requests','Create a request when a new caller is detected'],
      ['smsNotifications','SMS Notifications','Send job updates via text to clients'],
      ['afterHoursMsg','After-Hours Message','Play custom message outside business hours']
    ];
    features.forEach(function(f) {
      html += '<label style="display:flex;align-items:flex-start;gap:8px;padding:10px;background:var(--bg);border-radius:8px;cursor:pointer;">'
        + '<input type="checkbox" ' + (settings[f[0]] ? 'checked' : '') + ' onchange="Receptionist.toggleSetting(\'' + f[0] + '\',this.checked)" style="margin-top:2px;">'
        + '<div><div style="font-size:13px;font-weight:600;">' + f[1] + '</div>'
        + '<div style="font-size:11px;color:var(--text-light);">' + f[2] + '</div></div>'
        + '</label>';
    });
    html += '</div></div>';

    html += '</div>';
    return html;
  },

  showConnect: function() {
    var html = UI.field('Dialpad API Key', '<input type="text" id="dp-key" placeholder="Enter your Dialpad API key">')
      + UI.field('Business Phone Number', '<input type="text" id="dp-phone" placeholder="(914) 555-0123">')
      + '<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:12px;margin-top:12px;font-size:12px;color:#166534;">'
      + '<strong>Setup:</strong> Log into dialpad.com → Settings → API → Copy your API key. Calls & SMS will sync automatically.'
      + '</div>';
    UI.showModal('Connect Dialpad', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="Receptionist.connect()">Connect</button>'
    });
  },

  connect: function() {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    settings.connected = true;
    settings.provider = 'Dialpad';
    settings.phoneNumber = document.getElementById('dp-phone').value || 'Business line';
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
    UI.closeModal();
    UI.toast('Dialpad connected! ✅');
    App.render();
  },

  disconnect: function() {
    if (!confirm('Disconnect Dialpad?')) return;
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    settings.connected = false;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
    UI.toast('Dialpad disconnected');
    App.render();
  },

  selectProvider: function(name) {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    settings.provider = name;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
    App.render();
  },

  toggleSetting: function(key, val) {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    settings[key] = val;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
  },

  saveSetting: function(key, val) {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    settings[key] = val;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
  },

  toggleDay: function(day, enabled) {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    if (!settings.hours) settings.hours = {};
    if (!settings.hours[day]) settings.hours[day] = { open:'8:00', close:'17:00', enabled:true };
    settings.hours[day].enabled = enabled;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
  },

  setHour: function(day, field, val) {
    var settings = JSON.parse(localStorage.getItem('bm-receptionist-settings') || '{}');
    if (!settings.hours) settings.hours = {};
    if (!settings.hours[day]) settings.hours[day] = { open:'8:00', close:'17:00', enabled:true };
    settings.hours[day][field] = val;
    localStorage.setItem('bm-receptionist-settings', JSON.stringify(settings));
  },

  logCall: function() {
    var clients = DB.getAll('bm-clients');
    var opts = '<option value="">— No linked client —</option>';
    clients.slice(0, 50).forEach(function(c) { opts += '<option value="' + UI.esc(c.name) + '">' + UI.esc(c.name) + '</option>'; });

    var html = UI.field('Caller Name', '<input type="text" id="call-name" placeholder="John Smith">')
      + UI.field('Phone', '<input type="text" id="call-phone" placeholder="(914) 555-0123">')
      + UI.field('Type', '<select id="call-type"><option>inbound</option><option>outbound</option><option>missed</option></select>')
      + UI.field('Duration', '<input type="text" id="call-dur" placeholder="2:30">')
      + UI.field('Link to Client', '<select id="call-client">' + opts + '</select>')
      + UI.field('Notes', '<textarea id="call-notes" placeholder="Call notes..."></textarea>');

    UI.showModal('Log Call', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="Receptionist.saveCall()">Save</button>'
    });
  },

  saveCall: function() {
    DB.create('bm-call-log', {
      callerName: document.getElementById('call-name').value,
      phone: document.getElementById('call-phone').value,
      type: document.getElementById('call-type').value,
      duration: document.getElementById('call-dur').value,
      linkedClient: document.getElementById('call-client').value,
      notes: document.getElementById('call-notes').value,
      date: new Date().toISOString()
    });
    UI.closeModal();
    UI.toast('Call logged');
    App.render();
  },

  removeCall: function(id) {
    DB.remove('bm-call-log', id);
    UI.toast('Call removed');
    App.render();
  },

  composeSMS: function() {
    var html = UI.field('To', '<input type="text" id="sms-to" placeholder="Phone number or client name">')
      + UI.field('Message', '<textarea id="sms-msg" placeholder="Type your message..." style="min-height:100px;"></textarea>');
    UI.showModal('New SMS', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="UI.toast(\'SMS sent!\');UI.closeModal();">Send</button>'
    });
  },

  viewSMS: function(id) {
    var m = DB.getById('bm-sms-inbox', id);
    if (!m) return;
    m.read = true;
    DB.update('bm-sms-inbox', id, m);
    UI.showModal('SMS from ' + UI.esc(m.from || 'Unknown'), '<div style="font-size:14px;line-height:1.6;">' + UI.esc(m.message) + '</div>'
      + '<div style="margin-top:12px;font-size:11px;color:var(--text-light);">' + new Date(m.date).toLocaleString() + '</div>', {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Close</button>'
        + ' <button class="btn btn-primary" onclick="Receptionist.composeSMS()">Reply</button>'
    });
  },

  callback: function(phone) {
    UI.toast('Calling ' + phone + '...');
  },

  createRequest: function(name, phone) {
    DB.create('bm-requests', { clientName: name, phone: phone, source: 'Voicemail', status: 'new', notes: 'Created from voicemail', createdAt: new Date().toISOString() });
    UI.toast('Request created for ' + name);
  }
};

