/* ──── src/pages/treemeasure.js ──── */
/**
 * Branch Manager — Tree Measurement Tool
 * Measure tree height (tangent method) and DBH (circumference → diameter)
 * Links to estimator for instant price quotes
 */
var TreeMeasure = {

  // State
  height: null,
  dbh: null,

  render: function() {
    var html = '<div style="max-width:800px;margin:0 auto;">';

    // ── Height Calculator ──
    html += '<div class="card" style="margin-bottom:20px;">'
      + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;">'
      + '<div style="width:40px;height:40px;background:var(--accent-light);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:20px;">🌲</div>'
      + '<div><div style="font-weight:700;font-size:16px;">Tree Height</div>'
      + '<div style="font-size:12px;color:var(--text-light);">Tangent method — stand back, measure the angle up</div></div>'
      + '</div>';

    // Method selector
    html += '<div style="display:flex;gap:8px;margin-bottom:16px;">'
      + '<button class="btn btn-sm" id="method-angle" onclick="TreeMeasure.setMethod(\'angle\')" style="flex:1;padding:8px;font-size:13px;background:var(--accent);color:#fff;border:none;border-radius:6px;cursor:pointer;">Phone Angle</button>'
      + '<button class="btn btn-sm" id="method-manual" onclick="TreeMeasure.setMethod(\'manual\')" style="flex:1;padding:8px;font-size:13px;background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:6px;cursor:pointer;">Manual Entry</button>'
      + '</div>';

    // Phone angle method
    html += '<div id="angle-method">'
      + '<div style="background:var(--bg);border-radius:8px;padding:16px;margin-bottom:12px;">'
      + '<div style="font-size:13px;color:var(--text-light);margin-bottom:12px;">'
      + '<strong>How it works:</strong> Stand a known distance from the tree. Point your phone at the top of the tree — the accelerometer reads the angle. Height = distance × tan(angle) + your eye height.'
      + '</div>'

      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">'
      + '<div class="form-group"><label>Distance from tree (ft)</label>'
      + '<input type="number" id="tm-distance" value="50" min="1" step="1" onchange="TreeMeasure.calcHeight()" style="font-size:16px;"></div>'
      + '<div class="form-group"><label>Your eye height (ft)</label>'
      + '<input type="number" id="tm-eyeheight" value="5.5" min="1" step="0.5" onchange="TreeMeasure.calcHeight()" style="font-size:16px;"></div>'
      + '</div>'

      + '<div style="text-align:center;margin:16px 0;">'
      + '<div id="tm-angle-display" style="font-size:48px;font-weight:800;color:var(--accent);line-height:1;">0°</div>'
      + '<div style="font-size:12px;color:var(--text-light);margin-top:4px;">Tilt angle</div>'
      + '</div>'

      + '<button class="btn btn-primary" onclick="TreeMeasure.startAngleCapture()" id="tm-capture-btn" style="width:100%;padding:12px;font-size:15px;font-weight:600;">'
      + '📱 Point at Tree Top & Tap to Capture'
      + '</button>'
      + '<div id="tm-angle-status" style="font-size:12px;color:var(--text-light);text-align:center;margin-top:8px;"></div>'
      + '</div>'
      + '</div>';

    // Manual angle entry
    html += '<div id="manual-method" style="display:none;">'
      + '<div style="background:var(--bg);border-radius:8px;padding:16px;margin-bottom:12px;">'
      + '<div style="font-size:13px;color:var(--text-light);margin-bottom:12px;">'
      + '<strong>Manual:</strong> Use a clinometer or protractor app to measure the angle to the tree top, then enter values below.'
      + '</div>'
      + '<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;">'
      + '<div class="form-group"><label>Distance (ft)</label>'
      + '<input type="number" id="tm-distance-m" value="50" min="1" step="1" onchange="TreeMeasure.calcHeightManual()" style="font-size:16px;"></div>'
      + '<div class="form-group"><label>Angle (°)</label>'
      + '<input type="number" id="tm-angle-m" value="45" min="1" max="89" step="1" onchange="TreeMeasure.calcHeightManual()" style="font-size:16px;"></div>'
      + '<div class="form-group"><label>Eye height (ft)</label>'
      + '<input type="number" id="tm-eyeheight-m" value="5.5" min="1" step="0.5" onchange="TreeMeasure.calcHeightManual()" style="font-size:16px;"></div>'
      + '</div>'
      + '</div>'
      + '</div>';

    // Height result
    html += '<div id="tm-height-result" style="display:none;background:linear-gradient(135deg,#f0fdf4,#dcfce7);border-radius:10px;padding:16px;margin-bottom:8px;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;">'
      + '<div><div style="font-size:12px;color:#166534;font-weight:600;">ESTIMATED HEIGHT</div>'
      + '<div style="font-size:36px;font-weight:800;color:#15803d;" id="tm-height-val">—</div></div>'
      + '<div style="text-align:right;font-size:12px;color:#166534;" id="tm-height-detail"></div>'
      + '</div>'
      + '</div>';

    html += '</div>';

    // ── DBH Calculator ──
    html += '<div class="card" style="margin-bottom:20px;">'
      + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;">'
      + '<div style="width:40px;height:40px;background:#fef3c7;border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:20px;">📏</div>'
      + '<div><div style="font-weight:700;font-size:16px;">DBH (Diameter at Breast Height)</div>'
      + '<div style="font-size:12px;color:var(--text-light);">Measured at 4.5 ft from ground — the industry standard</div></div>'
      + '</div>';

    // DBH method selector
    html += '<div style="display:flex;gap:8px;margin-bottom:16px;">'
      + '<button class="btn btn-sm" id="dbh-tape" onclick="TreeMeasure.setDBHMethod(\'tape\')" style="flex:1;padding:8px;font-size:13px;background:var(--accent);color:#fff;border:none;border-radius:6px;cursor:pointer;">Tape Measure</button>'
      + '<button class="btn btn-sm" id="dbh-direct" onclick="TreeMeasure.setDBHMethod(\'direct\')" style="flex:1;padding:8px;font-size:13px;background:var(--bg);color:var(--text);border:1px solid var(--border);border-radius:6px;cursor:pointer;">Known Diameter</button>'
      + '</div>';

    // Tape method (circumference → diameter)
    html += '<div id="dbh-tape-method">'
      + '<div style="background:var(--bg);border-radius:8px;padding:16px;">'
      + '<div style="font-size:13px;color:var(--text-light);margin-bottom:12px;">'
      + 'Wrap a tape measure around the trunk at <strong>4.5 feet</strong> from the ground. Enter the circumference — we\'ll calculate the diameter.'
      + '</div>'
      + '<div class="form-group"><label>Circumference (inches)</label>'
      + '<input type="number" id="tm-circumference" placeholder="e.g. 75" min="1" step="0.5" onchange="TreeMeasure.calcDBH()" style="font-size:16px;"></div>'
      + '</div>'
      + '</div>';

    // Direct diameter
    html += '<div id="dbh-direct-method" style="display:none;">'
      + '<div style="background:var(--bg);border-radius:8px;padding:16px;">'
      + '<div style="font-size:13px;color:var(--text-light);margin-bottom:12px;">'
      + 'Enter the diameter directly if you already measured or estimated it.'
      + '</div>'
      + '<div class="form-group"><label>Diameter (inches)</label>'
      + '<input type="number" id="tm-diameter" placeholder="e.g. 24" min="1" step="0.5" onchange="TreeMeasure.calcDBHDirect()" style="font-size:16px;"></div>'
      + '</div>'
      + '</div>';

    // DBH result
    html += '<div id="tm-dbh-result" style="display:none;background:linear-gradient(135deg,#fffbeb,#fef3c7);border-radius:10px;padding:16px;margin-top:12px;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;">'
      + '<div><div style="font-size:12px;color:#92400e;font-weight:600;">DBH</div>'
      + '<div style="font-size:36px;font-weight:800;color:#b45309;" id="tm-dbh-val">—</div></div>'
      + '<div style="text-align:right;" id="tm-dbh-detail">'
      + '<div style="font-size:12px;color:#92400e;" id="tm-dbh-class"></div>'
      + '</div>'
      + '</div>'
      + '</div>';

    html += '</div>';

    // ── Quick Estimate ──
    html += '<div class="card" style="margin-bottom:20px;">'
      + '<div style="display:flex;align-items:center;gap:10px;margin-bottom:16px;">'
      + '<div style="width:40px;height:40px;background:var(--green-bg);border-radius:10px;display:flex;align-items:center;justify-content:center;font-size:20px;">💰</div>'
      + '<div><div style="font-weight:700;font-size:16px;">Quick Price Estimate</div>'
      + '<div style="font-size:12px;color:var(--text-light);">Based on DBH × $100/inch rule of thumb</div></div>'
      + '</div>';

    html += '<div id="tm-estimate" style="display:none;">'
      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:12px;">'
      + '<div class="form-group"><label>Complexity</label>'
      + '<select id="tm-complexity" onchange="TreeMeasure.calcEstimate()" style="font-size:14px;">'
      + '<option value="0.8">Easy — open area, no obstacles</option>'
      + '<option value="1" selected>Standard — typical residential</option>'
      + '<option value="1.3">Moderate — near structure/power lines</option>'
      + '<option value="1.6">Difficult — tight access, crane needed</option>'
      + '<option value="2">Hazardous — storm damage, hung up</option>'
      + '</select></div>'
      + '<div class="form-group"><label>Stump Grinding?</label>'
      + '<select id="tm-stump" onchange="TreeMeasure.calcEstimate()" style="font-size:14px;">'
      + '<option value="0">No</option>'
      + '<option value="1" selected>Yes — standard</option>'
      + '<option value="2">Yes — large/deep</option>'
      + '</select></div>'
      + '</div>'

      + '<div style="background:linear-gradient(135deg,var(--green-bg),var(--green-bg));border-radius:10px;padding:16px;">'
      + '<div style="display:flex;justify-content:space-between;align-items:center;">'
      + '<div><div style="font-size:12px;color:var(--green-dark);font-weight:600;">ESTIMATED REMOVAL PRICE</div>'
      + '<div style="font-size:36px;font-weight:800;color:var(--accent);" id="tm-price-val">—</div></div>'
      + '<div style="text-align:right;">'
      + '<div style="font-size:12px;color:var(--green-dark);" id="tm-price-breakdown"></div>'
      + '</div>'
      + '</div>'
      + '</div>'

      + '<div style="display:flex;gap:8px;margin-top:12px;">'
      + '<button class="btn btn-primary" onclick="TreeMeasure.openEstimator()" style="flex:1;">Open Full Estimator</button>'
      + '<button class="btn btn-outline" onclick="TreeMeasure.saveToQuote()" style="flex:1;">Add to Quote</button>'
      + '</div>'
      + '</div>';

    html += '<div id="tm-estimate-empty" style="text-align:center;padding:20px;color:var(--text-light);">'
      + '<p>Enter tree height or DBH above to see pricing estimate</p>'
      + '</div>';

    html += '</div>';

    // ── Reference Chart ──
    html += '<div class="card" style="margin-bottom:20px;">'
      + '<div style="font-weight:700;font-size:15px;margin-bottom:12px;">Quick Reference</div>'
      + '<table class="data-table" style="font-size:13px;">'
      + '<thead><tr><th>DBH</th><th>Tree Class</th><th>Typical Height</th><th>Base Price</th></tr></thead>'
      + '<tbody>'
      + '<tr><td>6-12"</td><td>Small</td><td>20-35 ft</td><td>$600-$1,200</td></tr>'
      + '<tr><td>12-18"</td><td>Medium</td><td>35-50 ft</td><td>$1,200-$1,800</td></tr>'
      + '<tr><td>18-24"</td><td>Large</td><td>50-70 ft</td><td>$1,800-$2,400</td></tr>'
      + '<tr><td>24-36"</td><td>Very Large</td><td>60-90 ft</td><td>$2,400-$3,600</td></tr>'
      + '<tr><td>36-48"</td><td>Massive</td><td>70-100+ ft</td><td>$3,600-$4,800</td></tr>'
      + '<tr><td>48"+</td><td>Heritage</td><td>80-120+ ft</td><td>$4,800+</td></tr>'
      + '</tbody></table>'
      + '</div>';

    html += '</div>';
    return html;
  },

  // ── Method Toggles ──
  setMethod: function(method) {
    document.getElementById('angle-method').style.display = method === 'angle' ? 'block' : 'none';
    document.getElementById('manual-method').style.display = method === 'manual' ? 'block' : 'none';
    document.getElementById('method-angle').style.background = method === 'angle' ? 'var(--accent)' : 'var(--bg)';
    document.getElementById('method-angle').style.color = method === 'angle' ? '#fff' : 'var(--text)';
    document.getElementById('method-angle').style.border = method === 'angle' ? 'none' : '1px solid var(--border)';
    document.getElementById('method-manual').style.background = method === 'manual' ? 'var(--accent)' : 'var(--bg)';
    document.getElementById('method-manual').style.color = method === 'manual' ? '#fff' : 'var(--text)';
    document.getElementById('method-manual').style.border = method === 'manual' ? 'none' : '1px solid var(--border)';
    if (method === 'manual') TreeMeasure.calcHeightManual();
  },

  setDBHMethod: function(method) {
    document.getElementById('dbh-tape-method').style.display = method === 'tape' ? 'block' : 'none';
    document.getElementById('dbh-direct-method').style.display = method === 'direct' ? 'block' : 'none';
    document.getElementById('dbh-tape').style.background = method === 'tape' ? 'var(--accent)' : 'var(--bg)';
    document.getElementById('dbh-tape').style.color = method === 'tape' ? '#fff' : 'var(--text)';
    document.getElementById('dbh-tape').style.border = method === 'tape' ? 'none' : '1px solid var(--border)';
    document.getElementById('dbh-direct').style.background = method === 'direct' ? 'var(--accent)' : 'var(--bg)';
    document.getElementById('dbh-direct').style.color = method === 'direct' ? '#fff' : 'var(--text)';
    document.getElementById('dbh-direct').style.border = method === 'direct' ? 'none' : '1px solid var(--border)';
  },

  // ── Phone Accelerometer for Angle ──
  _listening: false,
  _currentAngle: 0,

  startAngleCapture: function() {
    var btn = document.getElementById('tm-capture-btn');
    var status = document.getElementById('tm-angle-status');

    if (TreeMeasure._listening) {
      // Capture current angle
      TreeMeasure._listening = false;
      window.removeEventListener('deviceorientation', TreeMeasure._handleOrientation);
      btn.textContent = '📱 Point at Tree Top & Tap to Capture';
      btn.style.background = '';
      TreeMeasure.calcHeight();
      status.textContent = 'Angle captured! Tap again to re-measure.';
      return;
    }

    // Check for permission (iOS 13+)
    if (typeof DeviceOrientationEvent !== 'undefined' && typeof DeviceOrientationEvent.requestPermission === 'function') {
      DeviceOrientationEvent.requestPermission().then(function(state) {
        if (state === 'granted') {
          TreeMeasure._startListening();
        } else {
          status.textContent = 'Permission denied. Use Manual Entry instead.';
          TreeMeasure.setMethod('manual');
        }
      }).catch(function() {
        status.textContent = 'Could not access sensors. Use Manual Entry.';
        TreeMeasure.setMethod('manual');
      });
    } else if (window.DeviceOrientationEvent) {
      TreeMeasure._startListening();
    } else {
      status.textContent = 'Device orientation not supported. Use Manual Entry.';
      TreeMeasure.setMethod('manual');
    }
  },

  _startListening: function() {
    TreeMeasure._listening = true;
    var btn = document.getElementById('tm-capture-btn');
    btn.textContent = '🎯 TAP to lock angle';
    btn.style.background = '#dc2626';
    document.getElementById('tm-angle-status').textContent = 'Point phone at tree top...';
    window.addEventListener('deviceorientation', TreeMeasure._handleOrientation);
  },

  _handleOrientation: function(e) {
    // beta = front-to-back tilt (-180 to 180), 0 = flat, 90 = vertical
    var angle = e.beta || 0;
    // When holding phone vertical and tilting up, beta decreases from 90
    // We want the angle from horizontal: 90 - beta
    var tiltAngle = Math.max(0, Math.min(89, 90 - angle));
    TreeMeasure._currentAngle = tiltAngle;

    var display = document.getElementById('tm-angle-display');
    if (display) display.textContent = Math.round(tiltAngle) + '°';
  },

  // ── Height Calculations ──
  calcHeight: function() {
    var dist = parseFloat(document.getElementById('tm-distance').value) || 0;
    var eyeH = parseFloat(document.getElementById('tm-eyeheight').value) || 5.5;
    var angle = TreeMeasure._currentAngle;
    if (!dist || !angle) return;

    var radians = angle * Math.PI / 180;
    var height = dist * Math.tan(radians) + eyeH;
    TreeMeasure._showHeight(height, dist, angle, eyeH);
  },

  calcHeightManual: function() {
    var dist = parseFloat(document.getElementById('tm-distance-m').value) || 0;
    var angle = parseFloat(document.getElementById('tm-angle-m').value) || 0;
    var eyeH = parseFloat(document.getElementById('tm-eyeheight-m').value) || 5.5;
    if (!dist || !angle) return;

    var radians = angle * Math.PI / 180;
    var height = dist * Math.tan(radians) + eyeH;
    TreeMeasure._showHeight(height, dist, angle, eyeH);
  },

  _showHeight: function(height, dist, angle, eyeH) {
    TreeMeasure.height = Math.round(height);
    document.getElementById('tm-height-result').style.display = 'block';
    document.getElementById('tm-height-val').textContent = Math.round(height) + ' ft';
    document.getElementById('tm-height-detail').innerHTML =
      dist + ' ft back<br>' + Math.round(angle) + '° angle<br>' + eyeH + ' ft eye height';
    TreeMeasure.calcEstimate();
  },

  // ── DBH Calculations ──
  calcDBH: function() {
    var circ = parseFloat(document.getElementById('tm-circumference').value) || 0;
    if (!circ) return;
    var diameter = circ / Math.PI;
    TreeMeasure._showDBH(diameter, circ);
  },

  calcDBHDirect: function() {
    var diameter = parseFloat(document.getElementById('tm-diameter').value) || 0;
    if (!diameter) return;
    TreeMeasure._showDBH(diameter, diameter * Math.PI);
  },

  _showDBH: function(diameter, circumference) {
    TreeMeasure.dbh = Math.round(diameter * 10) / 10;
    document.getElementById('tm-dbh-result').style.display = 'block';
    document.getElementById('tm-dbh-val').textContent = TreeMeasure.dbh + '"';
    // Size class
    var cls = '';
    if (diameter < 12) cls = 'Small tree';
    else if (diameter < 18) cls = 'Medium tree';
    else if (diameter < 24) cls = 'Large tree';
    else if (diameter < 36) cls = 'Very large tree';
    else if (diameter < 48) cls = 'Massive tree';
    else cls = 'Heritage tree';
    document.getElementById('tm-dbh-detail').innerHTML =
      Math.round(circumference * 10) / 10 + '" circumference<br><span style="font-weight:600;">' + cls + '</span>';

    TreeMeasure.calcEstimate();
  },

  // ── Price Estimate ──
  calcEstimate: function() {
    var dbh = TreeMeasure.dbh;
    if (!dbh) return;

    document.getElementById('tm-estimate').style.display = 'block';
    document.getElementById('tm-estimate-empty').style.display = 'none';

    var complexity = parseFloat(document.getElementById('tm-complexity').value) || 1;
    var stumpOpt = parseInt(document.getElementById('tm-stump').value) || 0;

    // Base: $100/inch DBH
    var base = dbh * 100;
    var adjusted = base * complexity;

    // Stump grinding
    var stumpCost = 0;
    if (stumpOpt === 1) stumpCost = Math.max(150, dbh * 8);
    if (stumpOpt === 2) stumpCost = Math.max(250, dbh * 15);
    var total = adjusted + stumpCost;

    // Round to nearest $50
    total = Math.round(total / 50) * 50;

    document.getElementById('tm-price-val').textContent = '$' + total.toLocaleString();
    var breakdown = 'DBH: ' + dbh + '" × $100 = $' + Math.round(base).toLocaleString();
    if (complexity !== 1) breakdown += '<br>Complexity: ×' + complexity;
    if (stumpCost > 0) breakdown += '<br>Stump: +$' + Math.round(stumpCost).toLocaleString();
    if (TreeMeasure.height) breakdown += '<br>Height: ~' + TreeMeasure.height + ' ft';
    document.getElementById('tm-price-breakdown').innerHTML = breakdown;
  },

  // ── Actions ──
  openEstimator: function() {
    Estimator.show();
  },

  saveToQuote: function() {
    var dbh = TreeMeasure.dbh || 0;
    var height = TreeMeasure.height || 0;
    var complexity = document.getElementById('tm-complexity') ?
      document.getElementById('tm-complexity').options[document.getElementById('tm-complexity').selectedIndex].text : 'Standard';

    // Store measurement for quote form to pick up
    localStorage.setItem('bm-tree-measure', JSON.stringify({
      dbh: dbh,
      height: height,
      complexity: complexity,
      timestamp: new Date().toISOString()
    }));

    UI.toast('Measurement saved — opening new quote');
    loadPage('quotes');
    setTimeout(function() { QuotesPage.showForm(); }, 300);
  }
};

;
/* ──── src/pages/search.js ──── */
/**
 * Branch Manager — Global Search
 * Search across clients, jobs, invoices, quotes, requests
 * v2 — recent searches, category filters, result counts, better cards,
 *       quick actions, keyboard hint, text highlight, improved empty state
 */
var SearchPage = {
  _activeCategory: 'all',
  _RECENT_KEY: 'bm-recent-searches',
  _MAX_RECENT: 5,

  // ── Recent Searches ────────────────────────────────────────────
  _getRecent: function() {
    try { return JSON.parse(localStorage.getItem(SearchPage._RECENT_KEY) || '[]'); } catch(e) { return []; }
  },

  _saveRecent: function(query) {
    if (!query || query.trim().length < 2) return;
    var q = query.trim();
    var list = SearchPage._getRecent().filter(function(r) { return r !== q; });
    list.unshift(q);
    list = list.slice(0, SearchPage._MAX_RECENT);
    try { localStorage.setItem(SearchPage._RECENT_KEY, JSON.stringify(list)); } catch(e) {}
  },

  _clearRecent: function() {
    try { localStorage.removeItem(SearchPage._RECENT_KEY); } catch(e) {}
    loadPage('search');
  },

  // ── Text Highlight ─────────────────────────────────────────────
  _highlight: function(text, query) {
    if (!text || !query) return UI.esc(text || '');
    var escaped = UI.esc(text);
    var escapedQ = query.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    return escaped.replace(new RegExp('(' + escapedQ + ')', 'gi'),
      '<mark style="background:#fff176;padding:0 2px;border-radius:2px;">$1</mark>');
  },

  // ── Category selector ──────────────────────────────────────────
  _setCategory: function(cat) {
    SearchPage._activeCategory = cat;
    var searchEl = document.getElementById('search-page-input') || document.getElementById('global-search-input');
    var q = searchEl ? searchEl.value.trim() : '';
    var content = document.getElementById('search-results-area');
    if (content) content.innerHTML = SearchPage._renderResults(q);
  },

  // ── Main render ────────────────────────────────────────────────
  render: function(query) {
    var self = SearchPage;
    self._activeCategory = 'all';

    // Search input bar (always visible on the search page)
    var html = '<div style="position:relative;margin-bottom:16px;">'
      + '<input type="text" id="search-page-input" placeholder="Search clients, jobs, quotes, invoices..." '
      + 'value="' + UI.esc(query || '') + '" '
      + 'oninput="SearchPage._onPageSearch(this.value)" '
      + 'autocomplete="off" autocorrect="off" autocapitalize="off" '
      + 'style="width:100%;padding:12px 16px 12px 40px;border:2px solid var(--border);border-radius:12px;font-size:15px;background:var(--white);outline:none;-webkit-appearance:none;" '
      + 'onfocus="this.style.borderColor=\'var(--accent)\'" onblur="this.style.borderColor=\'var(--border)\'">'
      + '<span style="position:absolute;left:14px;top:50%;transform:translateY(-50%);font-size:16px;pointer-events:none;">🔍</span>'
      + '</div>';

    // Category filter tabs
    var cats = ['all', 'clients', 'jobs', 'invoices', 'quotes', 'requests'];
    html += '<div id="search-cat-tabs" style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:16px;overflow-x:auto;-webkit-overflow-scrolling:touch;">';
    cats.forEach(function(cat) {
      var active = self._activeCategory === cat;
      html += '<button onclick="SearchPage._setCategory(\'' + cat + '\')" id="search-tab-' + cat + '" style="'
        + 'padding:6px 14px;border-radius:20px;border:1px solid var(--border);font-size:13px;cursor:pointer;font-weight:600;white-space:nowrap;'
        + (active ? 'background:var(--green-dark);color:#fff;border-color:var(--green-dark);' : 'background:var(--white);color:var(--text-light);')
        + '">' + cat.charAt(0).toUpperCase() + cat.slice(1) + '</button>';
    });
    html += '</div>';

    // Results area (populated by _renderResults)
    html += '<div id="search-results-area">' + self._renderResults(query) + '</div>';

    return html;
  },

  // ── Live search from the page input ───────────────────────────
  _pageSearchTimeout: null,
  _onPageSearch: function(q) {
    clearTimeout(SearchPage._pageSearchTimeout);
    SearchPage._pageSearchTimeout = setTimeout(function() {
      var content = document.getElementById('search-results-area');
      if (content) content.innerHTML = SearchPage._renderResults(q);
    }, 200);
  },

  // ── Build result list HTML ─────────────────────────────────────
  _renderResults: function(query) {
    var self = SearchPage;
    var cat = self._activeCategory;

    // Update tab styles
    setTimeout(function() {
      ['all','clients','jobs','invoices','quotes','requests'].forEach(function(c) {
        var btn = document.getElementById('search-tab-' + c);
        if (!btn) return;
        if (c === cat) {
          btn.style.background = 'var(--green-dark)';
          btn.style.color = '#fff';
          btn.style.borderColor = 'var(--green-dark)';
        } else {
          btn.style.background = 'var(--white)';
          btn.style.color = 'var(--text-light)';
          btn.style.borderColor = 'var(--border)';
        }
      });
    }, 0);

    // Gather results — if no query, show ALL by most recent (Jobber-style)
    var isSearch = query && query.trim().length >= 2;
    var q = isSearch ? query.trim().toLowerCase() : '';

    if (isSearch) self._saveRecent(query.trim());

    var byType = { clients: [], jobs: [], invoices: [], quotes: [], requests: [] };

    if (isSearch) {
      byType.clients = DB.clients.search(q);
      byType.jobs = DB.jobs.search(q);
      byType.invoices = DB.invoices.search(q);
      byType.quotes = DB.quotes.search(q);
      byType.requests = DB.requests.search(q);
    } else {
      // No query — show all records sorted by most recent (updatedAt or createdAt)
      var sortRecent = function(a, b) { return (b.updatedAt || b.createdAt || '').localeCompare(a.updatedAt || a.createdAt || ''); };
      byType.clients = DB.clients.getAll().sort(sortRecent);
      byType.jobs = DB.jobs.getAll().sort(sortRecent);
      byType.invoices = DB.invoices.getAll().sort(sortRecent);
      byType.quotes = DB.quotes.getAll().sort(sortRecent);
      byType.requests = DB.requests.getAll().sort(sortRecent);
    }

    var totalClients   = byType.clients.length;
    var totalJobs      = byType.jobs.length;
    var totalInvoices  = byType.invoices.length;
    var totalQuotes    = byType.quotes.length;
    var totalRequests  = byType.requests.length;
    var grandTotal     = totalClients + totalJobs + totalInvoices + totalQuotes + totalRequests;

    if (grandTotal === 0 && isSearch) {
      return '<div class="empty-state" style="text-align:center;padding:40px 20px;">'
        + '<div style="font-size:48px;margin-bottom:12px;">🔍</div>'
        + '<h3 style="margin-bottom:8px;">No results for &ldquo;' + UI.esc(query) + '&rdquo;</h3>'
        + '<p style="color:var(--text-light);">Try searching for a client name, address, phone number, or invoice #.</p>'
        + '</div>';
    }
    if (grandTotal === 0) {
      return '<div class="empty-state" style="text-align:center;padding:40px 20px;">'
        + '<div style="font-size:48px;margin-bottom:12px;">📂</div>'
        + '<h3 style="margin-bottom:8px;">No records yet</h3>'
        + '<p style="color:var(--text-light);">Add clients, jobs, quotes, or invoices to see them here.</p>'
        + '</div>';
    }

    // Summary line
    var parts = [];
    if (totalClients)  parts.push(totalClients + ' client' + (totalClients !== 1 ? 's' : ''));
    if (totalJobs)     parts.push(totalJobs + ' job' + (totalJobs !== 1 ? 's' : ''));
    if (totalInvoices) parts.push(totalInvoices + ' invoice' + (totalInvoices !== 1 ? 's' : ''));
    if (totalQuotes)   parts.push(totalQuotes + ' quote' + (totalQuotes !== 1 ? 's' : ''));
    if (totalRequests) parts.push(totalRequests + ' request' + (totalRequests !== 1 ? 's' : ''));

    var html = '<div style="font-size:13px;color:var(--text-light);margin-bottom:16px;">'
      + parts.join(' &bull; ')
      + (isSearch ? ' for &ldquo;' + UI.esc(query) + '&rdquo;' : ' — most recent first')
      + '</div>';

    // Helper: render a section
    var PAGE_SIZE = cat === 'all' ? 15 : 100;
    function renderSection(title, icon, items, renderFn) {
      if (!items.length) return '';
      if (cat !== 'all' && cat !== title.toLowerCase()) return '';
      var sectionId = 'search-section-' + title.toLowerCase();
      var showing = Math.min(items.length, PAGE_SIZE);
      var out = '<div style="margin-bottom:20px;" id="' + sectionId + '">'
        + '<div style="font-size:12px;font-weight:700;color:var(--text-light);text-transform:uppercase;letter-spacing:.6px;margin-bottom:8px;">'
        + icon + ' ' + title + ' <span style="font-weight:400;">(' + items.length + ')</span></div>'
        + '<div style="background:var(--white);border-radius:12px;border:1px solid var(--border);overflow:hidden;">';
      items.slice(0, PAGE_SIZE).forEach(function(item, idx) {
        out += renderFn(item, idx === showing - 1 && items.length <= PAGE_SIZE);
      });
      if (items.length > PAGE_SIZE) {
        out += '<div style="padding:10px 16px;text-align:center;border-top:1px solid #f0f0f0;">'
          + '<button onclick="SearchPage._showMore(\'' + sectionId + '\',\'' + title.toLowerCase() + '\')" style="background:none;border:none;color:var(--accent);font-weight:700;font-size:13px;cursor:pointer;">Show all ' + items.length + ' ' + title.toLowerCase() + ' ↓</button>'
          + '</div>';
      }
      out += '</div></div>';
      return out;
    }

    function row(onclick, left, right, last) {
      return '<div onclick="' + onclick + '" style="display:flex;align-items:center;gap:12px;padding:14px 16px;'
        + (last ? '' : 'border-bottom:1px solid #f0f0f0;')
        + 'cursor:pointer;transition:background .1s;" onmouseover="this.style.background=\'#fafafa\'" onmouseout="this.style.background=\'\'"><div style="flex:1;min-width:0;">'
        + left + '</div>' + right + '</div>';
    }

    // Clients
    html += renderSection('Clients', '👥', byType.clients, function(c, last) {
      var allInv = DB.invoices.getAll().filter(function(i) { return i.clientId === c.id; });
      var balDue = allInv.reduce(function(s, i) { return s + (i.status !== 'paid' ? (i.balance || 0) : 0); }, 0);
      var left = '<div style="font-weight:600;font-size:14px;">' + self._highlight(c.name, query) + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);margin-top:2px;">'
        + (c.address ? self._highlight(c.address, query) + (c.phone ? ' &bull; ' : '') : '')
        + (c.phone ? self._highlight(c.phone, query) : '')
        + '</div>';
      var right = '<div style="text-align:right;flex-shrink:0;">'
        + UI.statusBadge(c.status)
        + (balDue > 0 ? '<div style="font-size:12px;color:var(--red);font-weight:600;margin-top:4px;">' + UI.money(balDue) + ' due</div>' : '')
        + '</div>';
      return row("ClientsPage._pendingDetail='" + c.id + "';loadPage('clients')", left, right, last);
    });

    // Jobs
    html += renderSection('Jobs', '🔧', byType.jobs, function(j, last) {
      var left = '<div style="font-weight:600;font-size:14px;">#' + j.jobNumber + ' — ' + self._highlight(j.clientName || '', query) + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);margin-top:2px;">'
        + (j.description ? self._highlight(j.description, query) : '')
        + (j.scheduledDate ? ' &bull; ' + UI.dateShort(j.scheduledDate) : '')
        + '</div>';
      var right = '<div style="text-align:right;flex-shrink:0;">'
        + UI.statusBadge(j.status)
        + (j.total ? '<div style="font-size:12px;font-weight:600;margin-top:4px;">' + UI.money(j.total) + '</div>' : '')
        + '</div>';
      return row("JobsPage._pendingDetail='" + j.id + "';loadPage('jobs')", left, right, last);
    });

    // Invoices
    html += renderSection('Invoices', '💰', byType.invoices, function(i, last) {
      var left = '<div style="font-weight:600;font-size:14px;">Invoice #' + i.invoiceNumber + ' — ' + self._highlight(i.clientName || '', query) + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);margin-top:2px;">'
        + (i.subject ? self._highlight(i.subject, query) + (i.dueDate ? ' &bull; ' : '') : '')
        + (i.dueDate ? 'Due ' + UI.dateShort(i.dueDate) : '')
        + '</div>';
      var right = '<div style="text-align:right;flex-shrink:0;">'
        + UI.statusBadge(i.status)
        + (i.balance > 0 ? '<div style="font-size:12px;color:var(--red);font-weight:600;margin-top:4px;">' + UI.money(i.balance) + ' due</div>'
          : (i.total ? '<div style="font-size:12px;font-weight:600;color:var(--green-dark);margin-top:4px;">' + UI.money(i.total) + ' paid</div>' : ''))
        + '</div>';
      return row("InvoicesPage._pendingDetail='" + i.id + "';loadPage('invoices')", left, right, last);
    });

    // Quotes
    html += renderSection('Quotes', '📋', byType.quotes, function(qr, last) {
      var left = '<div style="font-weight:600;font-size:14px;">Quote #' + qr.quoteNumber + ' — ' + self._highlight(qr.clientName || '', query) + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);margin-top:2px;">'
        + (qr.description ? self._highlight(qr.description, query) : '')
        + '</div>';
      var right = '<div style="text-align:right;flex-shrink:0;">'
        + UI.statusBadge(qr.status)
        + (qr.total ? '<div style="font-size:12px;font-weight:600;margin-top:4px;">' + UI.money(qr.total) + '</div>' : '')
        + '</div>';
      return row("QuotesPage._pendingDetail='" + qr.id + "';loadPage('quotes')", left, right, last);
    });

    // Requests
    html += renderSection('Requests', '📥', byType.requests, function(r, last) {
      var left = '<div style="font-weight:600;font-size:14px;">' + self._highlight(r.clientName || '', query) + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);margin-top:2px;">'
        + (r.property ? self._highlight(r.property, query) : '')
        + (r.source ? ' &bull; ' + UI.esc(r.source) : '')
        + '</div>';
      var right = UI.statusBadge(r.status);
      return row("RequestsPage._pendingDetail='" + r.id + "';loadPage('requests')", left, right, last);
    });

    return html;
  },

  // Re-run a recent search by populating the search bar + re-rendering
  _showMore: function(sectionId, type) {
    // Switch to that category tab which shows ALL items (no pagination for filtered view)
    SearchPage._activeCategory = type;
    var searchEl = document.getElementById('search-page-input');
    var q = searchEl ? searchEl.value.trim() : '';
    var content = document.getElementById('search-results-area');
    if (content) content.innerHTML = SearchPage._renderResults(q);
  },

  _runRecent: function(query) {
    var searchEl = document.getElementById('search-page-input') || document.getElementById('globalSearch');
    if (searchEl) {
      searchEl.value = query;
      searchEl.dispatchEvent(new Event('input'));
    }
    // Also update results area directly
    var content = document.getElementById('search-results-area');
    if (content) content.innerHTML = SearchPage._renderResults(query);
  }
};

;
/* ──── src/pages/clienthub.js ──── */
/**
 * Branch Manager — Client Hub
 * Client-facing portal where customers can:
 * - View their quotes and approve them
 * - See upcoming appointments
 * - View and pay invoices
 * - Submit new requests
 * - See job history
 *
 * Access: branchmanager.app/client.html?id=CLIENT_ID
 * (In production, this will be a separate page with its own auth)
 * v3 — stats bar, real newRequest modal, Send Portal Link button, Email Portal Link in preview
 */
var ClientHub = {
  _co: function() {
    return {
      name: CompanyInfo.get('name'),
      phone: CompanyInfo.get('phone'),
      email: CompanyInfo.get('email'),
      website: CompanyInfo.get('website')
    };
  },

  render: function() {
    var clients = DB.clients.getAll().slice(0, 200);
    clients.sort(function(a, b) { return (a.name || '').localeCompare(b.name || ''); });

    // Compute stats
    var allInvoices = DB.invoices.getAll();
    var allQuotes   = DB.quotes.getAll();

    var clientsWithUnpaid  = 0;
    var totalOutstanding   = 0;
    var totalPendingApprovals = 0;

    clients.forEach(function(c) {
      var inv = allInvoices.filter(function(i) { return i.clientId === c.id || (i.clientName || '').toLowerCase() === (c.name || '').toLowerCase(); });
      var unpaidBal = inv.reduce(function(s, i) { return s + (i.status !== 'paid' && i.balance > 0 ? (i.balance || 0) : 0); }, 0);
      if (unpaidBal > 0) clientsWithUnpaid++;
      totalOutstanding += unpaidBal;

      var pending = allQuotes.filter(function(q) {
        return (q.clientId === c.id || (q.clientName || '').toLowerCase() === (c.name || '').toLowerCase())
          && (q.status === 'sent' || q.status === 'awaiting');
      }).length;
      totalPendingApprovals += pending;
    });

    var html = '<div style="max-width:800px;">';

    // Stats bar
    html += '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:0;border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:16px;background:var(--white);" class="stat-row">'
      + '<div style="padding:14px 16px;border-right:1px solid var(--border);">'
      + '<div style="font-size:13px;color:var(--text-light);">Clients w/ unpaid invoices</div>'
      + '<div style="font-size:28px;font-weight:700;margin-top:4px;color:' + (clientsWithUnpaid > 0 ? 'var(--red)' : 'var(--green-dark)') + ';">' + clientsWithUnpaid + '</div>'
      + '</div>'
      + '<div style="padding:14px 16px;border-right:1px solid var(--border);">'
      + '<div style="font-size:13px;color:var(--text-light);">Total outstanding</div>'
      + '<div style="font-size:28px;font-weight:700;margin-top:4px;color:' + (totalOutstanding > 0 ? 'var(--red)' : 'var(--green-dark)') + ';">' + UI.money(totalOutstanding) + '</div>'
      + '</div>'
      + '<div style="padding:14px 16px;">'
      + '<div style="font-size:13px;color:var(--text-light);">Pending quote approvals</div>'
      + '<div style="font-size:28px;font-weight:700;margin-top:4px;color:' + (totalPendingApprovals > 0 ? '#e65100' : 'var(--green-dark)') + ';">' + totalPendingApprovals + '</div>'
      + '</div>'
      + '</div>';

    // Info banner
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:16px 20px;margin-bottom:20px;">'
      + '<div style="display:flex;align-items:center;gap:12px;">'
      + '<div style="font-size:32px;">🌳</div>'
      + '<div><div style="font-weight:700;font-size:15px;">Client Portal</div>'
      + '<div style="font-size:13px;color:var(--text-light);">Each client gets a private link to view quotes, approve work, pay invoices, and submit requests.</div></div>'
      + '</div>'
      + '<div style="margin-top:12px;display:flex;gap:8px;flex-wrap:wrap;">'
      + '<div style="font-size:12px;color:var(--text-light);padding:6px 12px;background:var(--bg);border-radius:20px;">✅ View & approve quotes</div>'
      + '<div style="font-size:12px;color:var(--text-light);padding:6px 12px;background:var(--bg);border-radius:20px;">💰 Pay invoices online</div>'
      + '<div style="font-size:12px;color:var(--text-light);padding:6px 12px;background:var(--bg);border-radius:20px;">📅 See appointments</div>'
      + '<div style="font-size:12px;color:var(--text-light);padding:6px 12px;background:var(--bg);border-radius:20px;">📥 Submit requests</div>'
      + '</div></div>';

    html += '<div style="margin-bottom:12px;"><input type="text" id="clienthub-search" placeholder="Search clients..." oninput="ClientHub._filterList(this.value)" style="width:100%;max-width:360px;padding:10px 14px;border:2px solid var(--border);border-radius:8px;font-size:14px;"></div>';
    html += '<div id="clienthub-list">';

    clients.forEach(function(c) {
      var cInvoices = allInvoices.filter(function(i) { return i.clientId === c.id || (i.clientName || '').toLowerCase() === (c.name || '').toLowerCase(); });
      var cQuotes   = allQuotes.filter(function(q) { return q.clientId === c.id || (q.clientName || '').toLowerCase() === (c.name || '').toLowerCase(); });
      var unpaidCount   = cInvoices.filter(function(i) { return i.status !== 'paid' && i.balance > 0; }).length;
      var pendingQuotes = cQuotes.filter(function(q) { return q.status === 'sent' || q.status === 'awaiting'; }).length;
      var link = ClientHub.getLink(c.id);
      var mailSubject = 'Your ' + ClientHub._co().name + ' Portal';
      var mailBody = 'Hi ' + (c.name ? c.name.split(' ')[0] : 'there') + ',\n\nHere is your private portal link to view quotes, approve work, pay invoices, and submit requests:\n\n' + link + '\n\nThank you,\n' + ClientHub._co().name + '\n' + ClientHub._co().phone;

      html += '<div class="client-hub-row" style="background:var(--white);border:1px solid var(--border);border-radius:10px;padding:12px 16px;margin-bottom:8px;display:flex;align-items:center;justify-content:space-between;gap:12px;">'
        + '<div style="display:flex;align-items:center;gap:10px;min-width:0;">'
        + '<div style="width:36px;height:36px;border-radius:50%;background:var(--accent-light);color:var(--accent);font-weight:700;display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0;">'
        + (c.name || '?').charAt(0).toUpperCase() + '</div>'
        + '<div style="min-width:0;">'
        + '<div style="font-weight:600;font-size:14px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + UI.esc(c.name || '') + '</div>'
        + '<div style="font-size:12px;color:var(--text-light);">'
        + (c.email || '') + (c.email && c.phone ? ' · ' : '') + (c.phone || '')
        + '</div></div></div>'
        + '<div style="display:flex;align-items:center;gap:8px;flex-shrink:0;flex-wrap:wrap;">'
        + (unpaidCount > 0 ? '<span style="font-size:11px;background:#fff3e0;color:#e65100;padding:3px 8px;border-radius:10px;font-weight:600;">' + unpaidCount + ' unpaid</span>' : '')
        + (pendingQuotes > 0 ? '<span style="font-size:11px;background:#e3f2fd;color:#1565c0;padding:3px 8px;border-radius:10px;font-weight:600;">' + pendingQuotes + ' quote' + (pendingQuotes > 1 ? 's' : '') + '</span>' : '')
        + '<button onclick="ClientHub.showForClient(\'' + c.id + '\')" style="background:var(--green-dark);color:#fff;border:none;padding:7px 14px;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer;">View Portal</button>'
        + '<button onclick="navigator.clipboard.writeText(\'' + link + '\').then(function(){UI.toast(\'Link copied!\');})" style="background:none;border:1px solid var(--border);padding:7px 10px;border-radius:6px;font-size:12px;cursor:pointer;" title="Copy link">🔗</button>'
        + (c.email ? '<button onclick="window.open(\'mailto:' + encodeURIComponent(c.email) + '?subject=' + encodeURIComponent(mailSubject) + '&body=' + encodeURIComponent(mailBody) + '\',\'_blank\')" style="background:none;border:1px solid var(--border);padding:7px 10px;border-radius:6px;font-size:12px;cursor:pointer;" title="Send portal link by email">📧</button>' : '')
        + '</div></div>';
    });

    html += '</div></div>';
    return html;
  },

  _filterList: function(query) {
    var rows = document.querySelectorAll('.client-hub-row');
    var q = (query || '').toLowerCase().trim();
    rows.forEach(function(row) {
      var text = row.textContent.toLowerCase();
      row.style.display = (!q || text.indexOf(q) > -1) ? '' : 'none';
    });
  },

  // Generate a shareable client portal link
  getLink: function(clientId) {
    return window.location.origin + window.location.pathname.replace('index.html', '') + 'client.html?id=' + clientId;
  },

  // Render client hub preview (for the admin to see what client sees)
  renderPreview: function(clientId) {
    var c = DB.clients.getById(clientId);
    if (!c) return '<div class="empty-state"><div class="empty-icon">👤</div><h3>Client not found</h3></div>';

    var clientJobs     = DB.jobs.getAll().filter(function(j) { return j.clientId === clientId; });
    var clientInvoices = DB.invoices.getAll().filter(function(i) { return i.clientId === clientId; });
    var clientQuotes   = DB.quotes.getAll().filter(function(q) { return q.clientId === clientId; });

    var html = '<div style="max-width:600px;margin:0 auto;">';

    // Header
    html += '<div style="text-align:center;padding:24px;background:var(--green-dark);border-radius:12px;color:#fff;margin-bottom:20px;">'
      + '<h2 style="margin-bottom:4px;">🌳 ' + ClientHub._co().name + '</h2>'
      + '<p style="opacity:.7;font-size:13px;">Client Portal for ' + UI.esc(c.name) + '</p>'
      + '</div>';

    // Quick Actions
    html += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:20px;">'
      + '<button class="btn btn-primary" style="padding:16px;font-size:14px;justify-content:center;" onclick="ClientHub.newRequest(\'' + clientId + '\')">📥 New Request</button>'
      + '<a href="tel:' + ClientHub._co().phone.replace(/\D/g,'') + '" class="btn btn-outline" style="padding:16px;font-size:14px;justify-content:center;text-decoration:none;">📞 Call Us</a>'
      + '</div>';

    // Pending Quotes
    var pendingQuotes = clientQuotes.filter(function(q) { return q.status === 'sent' || q.status === 'awaiting'; });
    if (pendingQuotes.length > 0) {
      html += '<div style="background:var(--white);border-radius:12px;border:2px solid #ff9800;padding:16px;margin-bottom:16px;">'
        + '<h3 style="font-size:15px;margin-bottom:12px;color:#e65100;">📋 Quotes Awaiting Your Approval</h3>';
      pendingQuotes.forEach(function(q) {
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid #f0f0f0;">'
          + '<div><strong>Quote #' + q.quoteNumber + '</strong><br><span style="font-size:12px;color:var(--text-light);">' + UI.esc(q.description || '') + '</span></div>'
          + '<div style="text-align:right;"><div style="font-size:1.2rem;font-weight:800;color:var(--green-dark);">' + UI.money(q.total) + '</div>'
          + '<button class="btn btn-primary" style="font-size:11px;padding:4px 12px;margin-top:4px;" onclick="ClientHub.approveQuote(\'' + q.id + '\')">Approve</button></div>'
          + '</div>';
      });
      html += '</div>';
    }

    // Upcoming Appointments
    var upcomingJobs = clientJobs.filter(function(j) { return j.status === 'scheduled' || j.status === 'in_progress'; });
    html += '<div style="background:var(--white);border-radius:12px;border:1px solid var(--border);padding:16px;margin-bottom:16px;">'
      + '<h3 style="font-size:15px;margin-bottom:12px;">📅 Upcoming Appointments</h3>';
    if (upcomingJobs.length > 0) {
      upcomingJobs.forEach(function(j) {
        html += '<div style="padding:10px 0;border-bottom:1px solid #f0f0f0;">'
          + '<div style="display:flex;justify-content:space-between;"><strong>' + UI.esc(j.description || 'Service') + '</strong>' + UI.statusBadge(j.status) + '</div>'
          + '<div style="font-size:13px;color:var(--text-light);margin-top:4px;">📍 ' + UI.esc(j.property || c.address || '') + '</div>'
          + '<div style="font-size:13px;color:var(--text-light);">📅 ' + UI.dateShort(j.scheduledDate) + '</div>'
          + '</div>';
      });
    } else {
      html += '<p style="font-size:14px;color:var(--text-light);text-align:center;padding:12px 0;">No upcoming appointments</p>';
    }
    html += '</div>';

    // Outstanding Invoices
    var unpaid = clientInvoices.filter(function(i) { return i.status !== 'paid' && i.balance > 0; });
    if (unpaid.length > 0) {
      html += '<div style="background:var(--white);border-radius:12px;border:2px solid var(--red);padding:16px;margin-bottom:16px;">'
        + '<h3 style="font-size:15px;margin-bottom:12px;color:var(--red);">💰 Outstanding Invoices</h3>';
      unpaid.forEach(function(inv) {
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:10px 0;border-bottom:1px solid #f0f0f0;">'
          + '<div><strong>Invoice #' + inv.invoiceNumber + '</strong><br><span style="font-size:12px;color:var(--text-light);">Due: ' + UI.dateShort(inv.dueDate) + '</span></div>'
          + '<div style="text-align:right;"><div style="font-size:1.2rem;font-weight:800;color:var(--red);">' + UI.money(inv.balance) + '</div>'
          + '<button class="btn btn-primary" style="font-size:11px;padding:4px 12px;margin-top:4px;" onclick="if(typeof Stripe!==\'undefined\'){Stripe.sendPaymentLink(\'' + inv.id + '\')}else{UI.toast(\'Payment not configured\',\'error\')}">Pay Now</button></div>'
          + '</div>';
      });
      html += '</div>';
    }

    // Past Invoices
    var paidInvoices = clientInvoices.filter(function(i) { return i.status === 'paid'; });
    if (paidInvoices.length > 0) {
      html += '<div style="background:var(--white);border-radius:12px;border:1px solid var(--border);padding:16px;margin-bottom:16px;">'
        + '<h3 style="font-size:15px;margin-bottom:12px;">✅ Payment History</h3>';
      paidInvoices.forEach(function(inv) {
        html += '<div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #f0f0f0;font-size:14px;">'
          + '<span>#' + inv.invoiceNumber + ' — ' + UI.esc(inv.subject || '') + '</span>'
          + '<span style="color:var(--green-dark);font-weight:600;">' + UI.money(inv.total) + ' ✓</span>'
          + '</div>';
      });
      html += '</div>';
    }

    // Contact
    html += '<div style="text-align:center;padding:20px;font-size:13px;color:var(--text-light);">'
      + ClientHub._co().name + '<br>' + ClientHub._co().phone + ' &bull; ' + ClientHub._co().email + '<br>' + ClientHub._co().website
      + '</div>';

    html += '</div>';
    return html;
  },

  // Admin: show client hub for a specific client
  showForClient: function(clientId) {
    var html = ClientHub.renderPreview(clientId);
    var c = DB.clients.getById(clientId);
    var link = ClientHub.getLink(clientId);
    var mailSubject = 'Your ' + ClientHub._co().name + ' Portal';
    var mailBody = 'Hi ' + (c && c.name ? c.name.split(' ')[0] : 'there') + ',\n\nHere is your private portal link:\n\n' + link + '\n\nThank you,\n' + ClientHub._co().name + '\n' + ClientHub._co().phone;

    html += '<div style="margin-top:16px;padding:16px;background:var(--bg);border-radius:10px;text-align:center;">'
      + '<div style="font-size:13px;color:var(--text-light);margin-bottom:8px;">Share this link with your client:</div>'
      + '<input type="text" value="' + UI.esc(link) + '" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:13px;text-align:center;" readonly onclick="this.select()">'
      + '<div style="display:flex;gap:8px;justify-content:center;margin-top:8px;flex-wrap:wrap;">'
      + '<button class="btn btn-primary" onclick="navigator.clipboard.writeText(\'' + UI.esc(link) + '\');UI.toast(\'Link copied!\')">🔗 Copy Link</button>'
      + (c && c.email ? '<button class="btn btn-outline" onclick="window.open(\'mailto:' + encodeURIComponent(c.email) + '?subject=' + encodeURIComponent(mailSubject) + '&body=' + encodeURIComponent(mailBody) + '\',\'_blank\')">📧 Email Portal Link</button>' : '')
      + '</div>'
      + '</div>';

    UI.showModal('Client Portal Preview', html, { wide: true });
  },

  approveQuote: function(quoteId) {
    DB.quotes.update(quoteId, { status: 'approved' });
    UI.toast('Quote approved!');
    UI.closeModal();
  },

  // Real request form modal — creates a DB record
  newRequest: function(clientId) {
    var c = DB.clients.getById(clientId);
    if (!c) { UI.toast('Client not found', 'error'); return; }

    var html = '<div style="display:flex;flex-direction:column;gap:14px;">'
      + '<div style="background:var(--bg);border-radius:8px;padding:10px 14px;font-size:13px;color:var(--text-light);">'
      + 'Submitting for: <strong>' + UI.esc(c.name || '') + '</strong>'
      + (c.email ? ' &bull; ' + UI.esc(c.email) : '')
      + '</div>'

      + '<div><label style="font-size:13px;font-weight:600;display:block;margin-bottom:4px;">Property Address</label>'
      + '<input id="chr-property" type="text" value="' + UI.esc(c.address || '') + '" placeholder="Service address" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:14px;box-sizing:border-box;"></div>'

      + '<div><label style="font-size:13px;font-weight:600;display:block;margin-bottom:4px;">Type of Service</label>'
      + '<select id="chr-source" style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + '<option value="Client Portal">Client Portal</option>'
      + '<option value="Phone">Phone</option>'
      + '<option value="Email">Email</option>'
      + '<option value="In-Person">In-Person</option>'
      + '</select></div>'

      + '<div><label style="font-size:13px;font-weight:600;display:block;margin-bottom:4px;">Description / Notes</label>'
      + '<textarea id="chr-notes" rows="4" placeholder="Describe the work needed..." style="width:100%;padding:10px;border:2px solid var(--border);border-radius:8px;font-size:14px;resize:vertical;box-sizing:border-box;"></textarea></div>'

      + '<div style="display:flex;gap:8px;justify-content:flex-end;">'
      + '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
      + '<button class="btn btn-primary" onclick="ClientHub._submitRequest(\'' + clientId + '\')">Submit Request</button>'
      + '</div></div>';

    UI.showModal('New Request — ' + UI.esc(c.name || ''), html);
  },

  _submitRequest: function(clientId) {
    var c = DB.clients.getById(clientId);
    if (!c) { UI.toast('Client not found', 'error'); return; }

    var property = document.getElementById('chr-property').value.trim();
    var source   = document.getElementById('chr-source').value;
    var notes    = document.getElementById('chr-notes').value.trim();

    if (!property) { UI.toast('Enter a property address', 'error'); return; }

    DB.requests.create({
      clientId:   c.id,
      clientName: c.name,
      property:   property,
      phone:      c.phone || '',
      email:      c.email || '',
      source:     source,
      notes:      notes,
      status:     'new'
    });

    UI.toast('Request created for ' + c.name);
    UI.closeModal();
    // Refresh the current view if we're on requests page
    if (window._currentPage === 'requests') {
      loadPage('requests');
    }
  }
};

