      + '<p style="margin:6px 0 0;font-size:13px;color:#a8d5a2;">Licensed &amp; Insured — Westchester &amp; Putnam Counties</p>'
      + '</td></tr>'
      // Body
      + '<tr><td style="padding:32px;">'
