/* ──── src/pages/reminders.js ──── */
/**
 * Branch Manager — Business Reminders / Admin
 * Track licenses, insurance, certs, and other expiring items.
 * Shows a popup on login when anything is due soon or expired.
 */
var Reminders = {
  _key: 'bm-reminders',

  // Default seed data — Second Nature's actual licenses + insurance types
  _defaults: [
    // Licenses
    { id: 'lic-wc', category: 'license', name: 'Arborist License — Westchester County', number: 'WC-32079', expiry: '', notes: 'Westchester County arborist license', renewalUrl: '', alertDays: 60 },
    { id: 'lic-pc', category: 'license', name: 'Arborist License — Putnam County', number: 'PC-50644', expiry: '', notes: 'Putnam County arborist license', renewalUrl: '', alertDays: 60 },
    // Insurance
    { id: 'ins-gl', category: 'insurance', name: 'General Liability Insurance', number: '', expiry: '', notes: 'Required for all commercial jobs', renewalUrl: '', alertDays: 30 },
    { id: 'ins-wc', category: 'insurance', name: 'Workers\' Compensation Insurance', number: '', expiry: '', notes: 'Required for all employees', renewalUrl: '', alertDays: 30 },
    { id: 'ins-auto', category: 'insurance', name: 'Commercial Auto Insurance', number: '', expiry: '', notes: 'Covers all company vehicles', renewalUrl: '', alertDays: 30 },
    { id: 'ins-equip', category: 'insurance', name: 'Inland Marine / Equipment Insurance', number: '', expiry: '', notes: 'Covers equipment and tools', renewalUrl: '', alertDays: 30 },
    // Registration
    { id: 'reg-biz', category: 'registration', name: 'Business Registration / LLC', number: '', expiry: '', notes: 'State business entity renewal', renewalUrl: '', alertDays: 60 },
  ],

  getAll: function() {
    var stored = localStorage.getItem(Reminders._key);
    if (!stored) {
      var defaults = JSON.parse(JSON.stringify(Reminders._defaults));
      localStorage.setItem(Reminders._key, JSON.stringify(defaults));
      return defaults;
    }
    return JSON.parse(stored);
  },

  save: function(reminder) {
    var all = Reminders.getAll();
    var idx = all.findIndex(function(r) { return r.id === reminder.id; });
    if (idx >= 0) { all[idx] = reminder; } else { all.push(reminder); }
    localStorage.setItem(Reminders._key, JSON.stringify(all));
  },

  remove: function(id) {
    var all = Reminders.getAll().filter(function(r) { return r.id !== id; });
    localStorage.setItem(Reminders._key, JSON.stringify(all));
  },

  // Return items that are expired or expiring within their alertDays window
  getAlerts: function() {
    var now = new Date();
    var alerts = [];
    Reminders.getAll().forEach(function(r) {
      if (!r.expiry) return; // no date set, skip
      var exp = new Date(r.expiry + 'T00:00:00');
      var daysUntil = Math.ceil((exp - now) / 86400000);
      var alertDays = r.alertDays || 30;
      if (daysUntil < 0) {
        alerts.push({ reminder: r, daysUntil: daysUntil, status: 'expired' });
      } else if (daysUntil <= alertDays) {
        alerts.push({ reminder: r, daysUntil: daysUntil, status: 'expiring' });
      }
    });
    // Sort: expired first, then soonest expiring
    alerts.sort(function(a, b) { return a.daysUntil - b.daysUntil; });
    return alerts;
  },

  // Show the login popup if there are alerts (once per session)
  checkLoginPopup: function() {
    // Only for owners
    if (typeof Auth !== 'undefined' && Auth.role !== 'owner') return;
    var sessionKey = 'bm-reminder-popup-' + new Date().toISOString().split('T')[0];
    if (localStorage.getItem(sessionKey)) return; // already shown today
    var alerts = Reminders.getAlerts();
    if (alerts.length === 0) return;
    localStorage.setItem(sessionKey, '1');
    Reminders._showPopup(alerts);
  },

  _showPopup: function(alerts) {
    var expired = alerts.filter(function(a) { return a.status === 'expired'; });
    var expiring = alerts.filter(function(a) { return a.status === 'expiring'; });

    var html = '';
    if (expired.length > 0) {
      html += '<div style="background:#fde8e8;border:1px solid #f5c6cb;border-radius:10px;padding:14px 16px;margin-bottom:12px;">'
        + '<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:#842029;margin-bottom:8px;">🚨 Expired — Action Required</div>';
      expired.forEach(function(a) {
        var daysAgo = Math.abs(a.daysUntil);
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid rgba(220,53,69,.15);">'
          + '<div><div style="font-weight:600;font-size:13px;color:#842029;">' + UI.esc(a.reminder.name) + '</div>'
          + (a.reminder.number ? '<div style="font-size:12px;color:#6b2430;"># ' + UI.esc(a.reminder.number) + '</div>' : '')
          + '</div>'
          + '<div style="text-align:right;flex-shrink:0;margin-left:12px;">'
          + '<div style="font-size:12px;font-weight:700;color:#842029;">Expired ' + daysAgo + ' day' + (daysAgo !== 1 ? 's' : '') + ' ago</div>'
          + '<div style="font-size:11px;color:#6b2430;">' + UI.dateShort(a.reminder.expiry) + '</div>'
          + '</div></div>';
      });
      html += '</div>';
    }
    if (expiring.length > 0) {
      html += '<div style="background:#fff3cd;border:1px solid #ffc107;border-radius:10px;padding:14px 16px;">'
        + '<div style="font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.05em;color:#664d03;margin-bottom:8px;">⏰ Expiring Soon</div>';
      expiring.forEach(function(a) {
        html += '<div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;border-bottom:1px solid rgba(255,193,7,.2);">'
          + '<div><div style="font-weight:600;font-size:13px;color:#664d03;">' + UI.esc(a.reminder.name) + '</div>'
          + (a.reminder.number ? '<div style="font-size:12px;color:#664d03;"># ' + UI.esc(a.reminder.number) + '</div>' : '')
          + '</div>'
          + '<div style="text-align:right;flex-shrink:0;margin-left:12px;">'
          + '<div style="font-size:12px;font-weight:700;color:#664d03;">' + (a.daysUntil === 0 ? 'Expires today' : 'In ' + a.daysUntil + ' day' + (a.daysUntil !== 1 ? 's' : '')) + '</div>'
          + '<div style="font-size:11px;color:#664d03;">' + UI.dateShort(a.reminder.expiry) + '</div>'
          + '</div></div>';
      });
      html += '</div>';
    }

    UI.showModal('⚠️ Compliance Reminders', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Dismiss</button>'
        + ' <button class="btn btn-primary" onclick="UI.closeModal();loadPage(\'reminders\')">Manage Reminders →</button>'
    });
  },

  // ── Page renderer ──
  render: function() {
    var all = Reminders.getAll();
    var now = new Date();
    var today = now.toISOString().split('T')[0];
    var alerts = Reminders.getAlerts();

    var expired = alerts.filter(function(a) { return a.status === 'expired'; }).length;
    var expiring = alerts.filter(function(a) { return a.status === 'expiring'; }).length;
    var upToDate = all.filter(function(r) { return r.expiry && r.expiry >= today; }).length - expiring;
    var noDate = all.filter(function(r) { return !r.expiry; }).length;

    var html = '<div style="display:flex;justify-content:flex-end;margin-bottom:12px;">'
      + '<button onclick="Reminders.showForm()" style="background:var(--green-dark);color:#fff;border:none;padding:8px 16px;border-radius:8px;font-weight:600;cursor:pointer;font-size:13px;">+ Add Reminder</button>'
      + '</div>';

    html += '<div class="stat-grid">'
      + (expired > 0 ? '<div class="stat-card" style="border-top:3px solid #dc3545;" onclick="Reminders._filterTo(\'expired\')">'
          + '<div class="stat-label">🚨 Expired</div>'
          + '<div class="stat-value" style="color:#dc3545;">' + expired + '</div>'
          + '<div class="stat-sub">Need immediate action</div></div>'
        : '<div class="stat-card" style="border-top:3px solid #00836c;">'
          + '<div class="stat-label">🚨 Expired</div>'
          + '<div class="stat-value" style="color:#00836c;">0</div>'
          + '<div class="stat-sub">All clear</div></div>')
      + (expiring > 0 ? '<div class="stat-card" style="border-top:3px solid #ffc107;" onclick="Reminders._filterTo(\'expiring\')">'
          + '<div class="stat-label">⏰ Expiring Soon</div>'
          + '<div class="stat-value" style="color:#e6a817;">' + expiring + '</div>'
          + '<div class="stat-sub">Review upcoming renewals</div></div>'
        : '<div class="stat-card" style="border-top:3px solid #00836c;">'
          + '<div class="stat-label">⏰ Expiring Soon</div>'
          + '<div class="stat-value" style="color:#00836c;">0</div>'
          + '<div class="stat-sub">No upcoming renewals</div></div>')
      + '<div class="stat-card" style="border-top:3px solid #00836c;">'
        + '<div class="stat-label">✓ Current</div>'
        + '<div class="stat-value" style="color:#00836c;">' + upToDate + '</div>'
        + '<div class="stat-sub">Valid & up to date</div></div>'
      + '<div class="stat-card">'
        + '<div class="stat-label">📋 No Date Set</div>'
        + '<div class="stat-value">' + noDate + '</div>'
        + '<div class="stat-sub">Add expiry dates</div></div>'
      + '</div>';

    // Categories
    var categories = ['license', 'insurance', 'registration', 'other'];
    var catLabels = { license: '🪪 Licenses', insurance: '🛡️ Insurance', registration: '📄 Registrations', other: '📌 Other' };

    categories.forEach(function(cat) {
      var items = all.filter(function(r) { return r.category === cat; });
      if (items.length === 0) return;

      html += '<div style="background:var(--white);border-radius:12px;border:1px solid var(--border);overflow:hidden;margin-bottom:16px;">'
        + '<div style="padding:14px 20px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;">'
        + '<h3 style="font-size:15px;font-weight:700;margin:0;">' + catLabels[cat] + '</h3>'
        + '<button class="btn btn-outline" style="font-size:12px;padding:5px 12px;" onclick="Reminders.showForm(\'' + cat + '\')">+ Add</button>'
        + '</div>'
        + '<table class="data-table"><thead><tr>'
        + '<th>Name</th><th>Number / ID</th><th>Expires</th><th>Status</th><th>Alert</th><th style="width:80px;"></th>'
        + '</tr></thead><tbody>';

      items.forEach(function(r) {
        var statusHtml, expiryHtml;
        if (!r.expiry) {
          statusHtml = '<span style="font-size:12px;color:var(--text-light);">No date</span>';
          expiryHtml = '<span style="color:var(--text-light);">—</span>';
        } else {
          var exp = new Date(r.expiry + 'T00:00:00');
          var daysUntil = Math.ceil((exp - now) / 86400000);
          expiryHtml = UI.dateShort(r.expiry);
          if (daysUntil < 0) {
            statusHtml = '<span style="display:inline-block;padding:2px 10px;background:#fde8e8;color:#842029;border-radius:10px;font-size:11px;font-weight:700;">🚨 Expired ' + Math.abs(daysUntil) + 'd ago</span>';
          } else if (daysUntil === 0) {
            statusHtml = '<span style="display:inline-block;padding:2px 10px;background:#fff3cd;color:#664d03;border-radius:10px;font-size:11px;font-weight:700;">⚠️ Expires Today</span>';
          } else if (daysUntil <= (r.alertDays || 30)) {
            statusHtml = '<span style="display:inline-block;padding:2px 10px;background:#fff3cd;color:#664d03;border-radius:10px;font-size:11px;font-weight:700;">⏰ ' + daysUntil + 'd left</span>';
          } else {
            statusHtml = '<span style="display:inline-block;padding:2px 10px;background:#e6f9f2;color:#00836c;border-radius:10px;font-size:11px;font-weight:700;">✓ Valid</span>';
          }
        }

        var rowStatus = !r.expiry ? 'none' : (function() { var exp = new Date(r.expiry + 'T00:00:00'); var d = Math.ceil((exp - now) / 86400000); return d < 0 ? 'expired' : d <= (r.alertDays || 30) ? 'expiring' : 'valid'; })();
        html += '<tr data-status="' + rowStatus + '">'
          + '<td><strong>' + UI.esc(r.name) + '</strong>'
          + (r.notes ? '<div style="font-size:12px;color:var(--text-light);">' + UI.esc(r.notes) + '</div>' : '')
          + '</td>'
          + '<td style="font-size:13px;font-family:monospace;">' + UI.esc(r.number || '—') + '</td>'
          + '<td style="font-weight:' + (r.expiry ? '600' : '400') + ';">' + expiryHtml + '</td>'
          + '<td>' + statusHtml + '</td>'
          + '<td style="font-size:12px;color:var(--text-light);">' + (r.alertDays || 30) + ' days</td>'
          + '<td style="white-space:nowrap;">'
          + '<button onclick="Reminders.showForm(null,\'' + r.id + '\')" style="background:none;border:none;cursor:pointer;font-size:13px;color:var(--accent);font-weight:600;padding:4px 6px;">Edit</button>'
          + '<button onclick="Reminders._confirmRemove(\'' + r.id + '\')" style="background:none;border:none;cursor:pointer;font-size:13px;color:var(--red);padding:4px 6px;">✕</button>'
          + '</td>'
          + '</tr>';
      });

      html += '</tbody></table></div>';
    });

    // Add buttons for any missing categories
    html += '<div style="display:flex;gap:8px;flex-wrap:wrap;">';
    categories.forEach(function(cat) {
      html += '<button class="btn btn-outline" style="font-size:12px;" onclick="Reminders.showForm(\'' + cat + '\')">'
        + catLabels[cat] + ' — Add New</button>';
    });
    html += '</div>';

    return html;
  },

  showForm: function(defaultCat, reminderId) {
    var r = reminderId ? Reminders.getAll().find(function(x) { return x.id === reminderId; }) : {};
    if (!r) r = {};
    var title = reminderId ? 'Edit Reminder' : 'Add Reminder';

    var html = '<form id="reminder-form" onsubmit="Reminders.saveForm(event,\'' + (reminderId || '') + '\')">'
      + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">'
      + '<div class="form-group" style="grid-column:1/-1;"><label>Name *</label>'
      + '<input type="text" id="rm-name" value="' + UI.esc(r.name || '') + '" placeholder="e.g., General Liability Insurance" required style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;"></div>'
      + '<div class="form-group"><label>Category</label>'
      + '<select id="rm-category" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + ['license','insurance','registration','other'].map(function(c) {
          var labels = { license:'License', insurance:'Insurance', registration:'Registration', other:'Other' };
          return '<option value="' + c + '"' + ((r.category || defaultCat) === c ? ' selected' : '') + '>' + labels[c] + '</option>';
        }).join('')
      + '</select></div>'
      + '<div class="form-group"><label>Policy / License #</label>'
      + '<input type="text" id="rm-number" value="' + UI.esc(r.number || '') + '" placeholder="e.g., WC-32079" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;"></div>'
      + '<div class="form-group"><label>Expiration Date *</label>'
      + '<input type="date" id="rm-expiry" value="' + (r.expiry || '') + '" required style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;"></div>'
      + '<div class="form-group"><label>Alert Me (days before)</label>'
      + '<select id="rm-alert" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;">'
      + [7, 14, 30, 60, 90].map(function(d) { return '<option value="' + d + '"' + ((r.alertDays || 30) === d ? ' selected' : '') + '>' + d + ' days before</option>'; }).join('')
      + '</select></div>'
      + '<div class="form-group" style="grid-column:1/-1;"><label>Notes</label>'
      + '<input type="text" id="rm-notes" value="' + UI.esc(r.notes || '') + '" placeholder="Optional notes" style="width:100%;padding:9px 12px;border:2px solid var(--border);border-radius:8px;font-size:14px;"></div>'
      + '</div></form>';

    UI.showModal(title, html, {
      footer: (reminderId ? '<button class="btn btn-danger" style="margin-right:auto;" onclick="Reminders._confirmRemove(\'' + reminderId + '\')">Delete</button>' : '')
        + '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="document.getElementById(\'reminder-form\').requestSubmit()">Save</button>'
    });
  },

  saveForm: function(e, reminderId) {
    e.preventDefault();
    var reminder = {
      id: reminderId || ('rm-' + Date.now().toString(36)),
      category: document.getElementById('rm-category').value,
      name: document.getElementById('rm-name').value.trim(),
      number: document.getElementById('rm-number').value.trim(),
      expiry: document.getElementById('rm-expiry').value,
      alertDays: parseInt(document.getElementById('rm-alert').value),
      notes: document.getElementById('rm-notes').value.trim()
    };
    if (!reminder.name) { UI.toast('Name is required', 'error'); return; }
    Reminders.save(reminder);
    UI.toast(reminderId ? 'Reminder updated' : 'Reminder added');
    UI.closeModal();
    loadPage('reminders');
  },

  _confirmRemove: function(id) {
    UI.confirm('Delete this reminder?', function() {
      Reminders.remove(id);
      UI.toast('Reminder removed');
      UI.closeModal();
      loadPage('reminders');
    });
  },

  _filterTo: function(status) {
    // Highlight rows matching this status by scrolling to the first match
    var rows = document.querySelectorAll('#pageContent tr[data-status]');
    for (var i = 0; i < rows.length; i++) {
      if (rows[i].dataset.status === status) {
        rows[i].scrollIntoView({ behavior: 'smooth', block: 'center' });
        rows[i].style.background = 'rgba(220,53,69,0.08)';
        setTimeout(function(r) { r.style.background = ''; }, 2000, rows[i]);
        break;
      }
    }
    // Fallback: scroll to the list section
    var table = document.querySelector('#pageContent .data-table');
    if (table && !rows.length) table.scrollIntoView({ behavior: 'smooth' });
  }
};

;
/* ──── src/pages/payroll.js ──── */
/**
 * Branch Manager — Payroll + Week View
 * Gusto-style weekly timesheet with approval system
 * Mobile-first, iPhone-optimized
 * v1
 */
var PayrollPage = {
  _weekOffset: 0,
  _expandedCells: {},
  _selectedEmployees: {},
  _approvals: null,

  // ── Helpers ──
  _getWeekDates: function(offset) {
    var now = new Date();
    now.setDate(now.getDate() + (offset || 0) * 7);
    var monday = new Date(now);
    monday.setDate(monday.getDate() - ((monday.getDay() + 6) % 7));
    var dates = [];
    for (var i = 0; i < 7; i++) {
      var d = new Date(monday);
      d.setDate(d.getDate() + i);
      dates.push(d.toISOString().split('T')[0]);
    }
    return dates;
  },

  _getApprovals: function() {
    if (!PayrollPage._approvals) {
      try { PayrollPage._approvals = JSON.parse(localStorage.getItem('bm-payroll-approvals') || '{}'); } catch(e) { PayrollPage._approvals = {}; }
    }
    return PayrollPage._approvals;
  },

  _saveApprovals: function() {
    localStorage.setItem('bm-payroll-approvals', JSON.stringify(PayrollPage._approvals || {}));
  },

  _getEmployees: function() {
    var team = JSON.parse(localStorage.getItem('bm-team') || '[]');
    if (team.length === 0) {
      team = [{ id: 'owner', name: 'Doug Brown', role: 'owner', rate: 0, active: true }];
    }
    return team.filter(function(t) { return t.active !== false; });
  },

  _getEntriesForDate: function(userId, date) {
    return DB.timeEntries.getAll().filter(function(t) {
      var user = t.userId || t.user || '';
      var entryDate = (t.date || (t.clockIn || '').substring(0, 10));
      return user === userId && entryDate === date;
    });
  },

  _totalHours: function(entries) {
    return entries.reduce(function(s, e) { return s + (e.hours || 0); }, 0);
  },

  _hasIssues: function(entries, date) {
    var issues = [];
    if (entries.length === 0) return issues;
    entries.forEach(function(e) {
      if (e.clockIn && !e.clockOut) issues.push('Missing clock-out');
      if (!e.hours && !e.clockIn) issues.push('Missing hours');
    });
    return issues;
  },

  _approvalKey: function(userId, weekStart) {
    return userId + '_' + weekStart;
  },

  _dayApprovalKey: function(userId, date) {
    return userId + '_day_' + date;
  },

  // ── Main Render ──
  render: function() {
    var self = PayrollPage;
    var dates = self._getWeekDates(self._weekOffset);
    var employees = self._getEmployees();
    var weekStart = dates[0];
    var weekEnd = dates[6];
    var dayNames = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
    var today = new Date().toISOString().split('T')[0];
    var approvals = self._getApprovals();

    var html = '<div style="max-width:100%;overflow-x:auto;-webkit-overflow-scrolling:touch;">';

    // ── Week Navigator ──
    html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px;flex-wrap:wrap;gap:8px;">'
      + '<button onclick="PayrollPage._weekOffset--;loadPage(\'payroll\')" style="background:var(--white);border:1px solid var(--border);border-radius:8px;padding:8px 14px;cursor:pointer;font-size:14px;">← Prev</button>'
      + '<div style="text-align:center;">'
      + '<div style="font-size:18px;font-weight:800;">Week of ' + new Date(weekStart).toLocaleDateString('en-US', { month:'short', day:'numeric' }) + ' – ' + new Date(weekEnd).toLocaleDateString('en-US', { month:'short', day:'numeric', year:'numeric' }) + '</div>'
      + (self._weekOffset === 0 ? '<span style="font-size:11px;color:var(--green-dark);font-weight:600;">Current Week</span>' : '<button onclick="PayrollPage._weekOffset=0;loadPage(\'payroll\')" style="font-size:11px;color:var(--accent);background:none;border:none;cursor:pointer;text-decoration:underline;">Go to current week</button>')
      + '</div>'
      + '<button onclick="PayrollPage._weekOffset++;loadPage(\'payroll\')" style="background:var(--white);border:1px solid var(--border);border-radius:8px;padding:8px 14px;cursor:pointer;font-size:14px;">Next →</button>'
      + '</div>';

    // ── Bulk Actions ──
    html += '<div style="display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap;">'
      + '<button onclick="PayrollPage.approveAll(\'' + weekStart + '\')" class="btn btn-primary" style="font-size:12px;">✓ Approve All</button>'
      + '<button onclick="PayrollPage.showPayrollSummary(\'' + weekStart + '\')" class="btn btn-outline" style="font-size:12px;">📊 Payroll Summary</button>'
      + '<button onclick="PayrollPage.exportWeek(\'' + weekStart + '\')" class="btn btn-outline" style="font-size:12px;">📥 Export CSV</button>'
      + '<button onclick="window.open(\'onboarding/\',\'_blank\')" class="btn btn-outline" style="font-size:12px;">🎓 Onboarding</button>'
      + '</div>';

    // ── Week Grid ──
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;overflow:hidden;">';

    // Header row
    html += '<div style="display:grid;grid-template-columns:140px repeat(7,1fr) 70px;border-bottom:2px solid var(--border);font-size:11px;font-weight:700;color:var(--text-light);text-transform:uppercase;letter-spacing:.5px;">'
      + '<div style="padding:10px 12px;">Employee</div>';
    dates.forEach(function(d, i) {
      var isToday = d === today;
      html += '<div style="padding:10px 6px;text-align:center;' + (isToday ? 'background:var(--green-bg);color:var(--green-dark);' : '') + '">'
        + dayNames[i] + '<br><span style="font-weight:400;font-size:10px;">' + new Date(d).getDate() + '</span></div>';
    });
    html += '<div style="padding:10px 6px;text-align:center;">Total</div>';
    html += '</div>';

    // Employee rows
    employees.forEach(function(emp) {
      var weekTotal = 0;
      var weekIssues = 0;
      var empKey = self._approvalKey(emp.name || emp.id, weekStart);
      var weekApproved = approvals[empKey] === 'approved';

      html += '<div style="display:grid;grid-template-columns:140px repeat(7,1fr) 70px;border-bottom:1px solid #f0f0f0;align-items:stretch;">';

      // Employee name cell
      html += '<div style="padding:10px 12px;display:flex;align-items:center;gap:8px;border-right:1px solid #f0f0f0;">'
        + '<div style="width:28px;height:28px;border-radius:50%;background:var(--accent);color:#fff;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;flex-shrink:0;">'
        + (emp.name || '?').charAt(0).toUpperCase() + '</div>'
        + '<div style="min-width:0;"><div style="font-weight:600;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + UI.esc(emp.name || '') + '</div>'
        + '<div style="font-size:10px;color:var(--text-light);">' + UI.esc(emp.role || '') + '</div></div>'
        + '</div>';

      // Day cells
      dates.forEach(function(date) {
        var entries = self._getEntriesForDate(emp.name || emp.id, date);
        var dayHours = self._totalHours(entries);
        weekTotal += dayHours;
        var issues = self._hasIssues(entries, date);
        if (issues.length) weekIssues++;
        var isToday = date === today;
        var cellKey = (emp.name || emp.id) + '_' + date;
        var expanded = self._expandedCells[cellKey];
        var dayKey = self._dayApprovalKey(emp.name || emp.id, date);
        var dayApproved = approvals[dayKey] === 'approved';
        var barColor = issues.length > 0 ? '#ef4444' : (dayHours > 0 ? '#22c55e' : '#e5e7eb');
        var editedAfterApproval = dayApproved && approvals[dayKey + '_editedAfter'];

        if (editedAfterApproval) barColor = '#f59e0b';

        html += '<div onclick="PayrollPage._toggleCell(\'' + cellKey + '\')" style="padding:6px 4px;text-align:center;cursor:pointer;border-right:1px solid #f8f8f8;' + (isToday ? 'background:#f0fdf4;' : '') + 'position:relative;min-height:50px;">';

        // Hours
        html += '<div style="font-size:14px;font-weight:' + (dayHours > 0 ? '700' : '400') + ';color:' + (dayHours > 0 ? 'var(--text)' : '#ccc') + ';">' + (dayHours > 0 ? dayHours.toFixed(1) : '—') + '</div>';

        // Status bar (collapsed)
        html += '<div style="height:' + (expanded ? '0' : '4') + 'px;background:' + barColor + ';border-radius:2px;margin:4px 2px 0;transition:height .2s;"></div>';

        // Icons
        if (entries.some(function(e) { return e.notes; })) html += '<span style="font-size:9px;position:absolute;top:2px;right:3px;">📝</span>';

        // Expanded content
        if (expanded) {
          html += '<div style="margin-top:6px;text-align:left;font-size:11px;" onclick="event.stopPropagation()">';
          // Status bar expanded
          html += '<div style="height:6px;background:' + barColor + ';border-radius:3px;margin-bottom:6px;"></div>';
          if (issues.length) {
            issues.forEach(function(iss) {
              html += '<div style="color:#ef4444;font-size:10px;">⚠ ' + iss + '</div>';
            });
          }
          entries.forEach(function(e) {
            html += '<div style="font-size:10px;color:var(--text-light);margin-top:2px;">'
              + (e.clockIn ? new Date(e.clockIn).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '') + (e.clockOut ? '–' + new Date(e.clockOut).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : '') + ' ' + (e.hours ? e.hours.toFixed(1) + 'h' : '')
              + '</div>';
            if (e.notes) html += '<div style="font-size:10px;color:var(--text-light);font-style:italic;">' + UI.esc(e.notes) + '</div>';
          });
          // Day detail button
          html += '<button onclick="event.stopPropagation();PayrollPage.showDayDetail(\'' + UI.esc(emp.name || emp.id) + '\',\'' + date + '\')" style="margin-top:4px;font-size:10px;background:var(--accent);color:#fff;border:none;padding:3px 8px;border-radius:4px;cursor:pointer;">Details</button>';
          // Approval indicator
          if (dayApproved && !editedAfterApproval) html += '<div style="font-size:9px;color:#22c55e;margin-top:2px;">✓ Approved</div>';
          if (editedAfterApproval) html += '<div style="font-size:9px;color:#f59e0b;margin-top:2px;">⚠ Re-approval needed</div>';
          html += '</div>';
        }

        html += '</div>';
      });

      // Weekly total
      var overtime = Math.max(0, weekTotal - 40);
      html += '<div style="padding:10px 6px;text-align:center;font-weight:800;font-size:15px;background:' + (weekApproved ? '#f0fdf4' : 'var(--bg)') + ';border-left:2px solid var(--border);">'
        + weekTotal.toFixed(1)
        + (overtime > 0 ? '<div style="font-size:10px;color:#ef4444;font-weight:600;">' + overtime.toFixed(1) + ' OT</div>' : '')
        + (weekApproved ? '<div style="font-size:9px;color:#22c55e;">✓</div>' : '')
        + (weekIssues > 0 ? '<div style="font-size:9px;color:#ef4444;">' + weekIssues + ' issues</div>' : '')
        + '</div>';

      html += '</div>'; // end employee row
    });

    html += '</div>'; // end grid

    // ── Weekly Review Panel ──
    html += PayrollPage._renderWeeklyReview(dates, employees, weekStart);

    // v383: My Pay (employeecenter) folded under Payroll. Link at bottom for now;
    // will pull out to its own page once Crew View ships and crew-vs-admin nav splits.
    html += '<div style="margin-top:24px;padding:14px 16px;background:var(--bg);border:1px solid var(--border);border-radius:10px;display:flex;align-items:center;justify-content:space-between;gap:12px;">'
      +   '<div><strong style="font-size:13px;">My Pay & Hours</strong><div style="font-size:11px;color:var(--text-light);margin-top:2px;">Personal view: paystubs, hours worked, time off.</div></div>'
      +   '<button onclick="loadPage(\'employeecenter\')" class="btn btn-outline" style="font-size:12px;">Open My Pay &rarr;</button>'
      + '</div>';

    html += '</div>';
    return html;
  },

  // ── Weekly Review Panel ──
  _renderWeeklyReview: function(dates, employees, weekStart) {
    var approvals = PayrollPage._getApprovals();
    var totalHours = 0, totalOT = 0, totalPTO = 0;
    var warnings = [];
    var approved = 0, pending = 0;

    employees.forEach(function(emp) {
      var empWeek = 0;
      dates.forEach(function(d) {
        var entries = PayrollPage._getEntriesForDate(emp.name || emp.id, d);
        empWeek += PayrollPage._totalHours(entries);
        var issues = PayrollPage._hasIssues(entries, d);
        issues.forEach(function(iss) { warnings.push(emp.name + ' (' + d + '): ' + iss); });
      });
      totalHours += empWeek;
      var ot = Math.max(0, empWeek - 40);
      totalOT += ot;

      var empKey = PayrollPage._approvalKey(emp.name || emp.id, weekStart);
      if (approvals[empKey] === 'approved') approved++;
      else pending++;
    });

    var allApproved = pending === 0 && approved > 0;
    var payrollReady = allApproved && warnings.length === 0;

    var html = '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;padding:20px;margin-top:16px;">';
    html += '<h3 style="font-size:16px;margin:0 0 16px;">Weekly Review</h3>';

    // Stats
    html += '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:10px;margin-bottom:16px;">';
    html += '<div style="text-align:center;padding:12px;background:var(--bg);border-radius:10px;"><div style="font-size:22px;font-weight:800;">' + totalHours.toFixed(1) + '</div><div style="font-size:11px;color:var(--text-light);">Total Hours</div></div>';
    html += '<div style="text-align:center;padding:12px;background:' + (totalOT > 0 ? '#fef3c7' : 'var(--bg)') + ';border-radius:10px;"><div style="font-size:22px;font-weight:800;color:' + (totalOT > 0 ? '#d97706' : 'var(--text)') + ';">' + totalOT.toFixed(1) + '</div><div style="font-size:11px;color:var(--text-light);">Overtime</div></div>';
    html += '<div style="text-align:center;padding:12px;background:var(--bg);border-radius:10px;"><div style="font-size:22px;font-weight:800;">' + totalPTO.toFixed(1) + '</div><div style="font-size:11px;color:var(--text-light);">PTO</div></div>';
    html += '<div style="text-align:center;padding:12px;background:' + (warnings.length > 0 ? '#fef2f2' : 'var(--bg)') + ';border-radius:10px;"><div style="font-size:22px;font-weight:800;color:' + (warnings.length > 0 ? '#dc2626' : 'var(--text)') + ';">' + warnings.length + '</div><div style="font-size:11px;color:var(--text-light);">Warnings</div></div>';
    html += '<div style="text-align:center;padding:12px;background:' + (allApproved ? '#f0fdf4' : '#fef3c7') + ';border-radius:10px;"><div style="font-size:22px;font-weight:800;color:' + (allApproved ? '#16a34a' : '#d97706') + ';">' + approved + '/' + (approved + pending) + '</div><div style="font-size:11px;color:var(--text-light);">Approved</div></div>';
    html += '</div>';

    // Payroll readiness
    html += '<div style="padding:14px;border-radius:10px;background:' + (payrollReady ? '#f0fdf4;border:2px solid #22c55e' : '#fef3c7;border:2px solid #f59e0b') + ';display:flex;align-items:center;gap:12px;">'
      + '<div style="font-size:28px;">' + (payrollReady ? '✅' : '⏳') + '</div>'
      + '<div><div style="font-weight:700;font-size:14px;color:' + (payrollReady ? '#166534' : '#92400e') + ';">' + (payrollReady ? 'Payroll Ready' : 'Payroll Not Ready') + '</div>'
      + '<div style="font-size:12px;color:' + (payrollReady ? '#166534' : '#92400e') + ';">'
      + (payrollReady ? 'All hours approved, no warnings. Ready to sync with Gusto.' : (pending > 0 ? pending + ' employee(s) pending approval. ' : '') + (warnings.length > 0 ? warnings.length + ' warning(s) to resolve.' : ''))
      + '</div></div>'
      + (payrollReady ? '<button onclick="PayrollPage.triggerGusto(\'' + weekStart + '\')" class="btn btn-primary" style="margin-left:auto;white-space:nowrap;">🚀 Send to Gusto</button>' : '')
      + '</div>';

    // Warnings list
    if (warnings.length > 0) {
      html += '<div style="margin-top:12px;">';
      warnings.slice(0, 10).forEach(function(w) {
        html += '<div style="font-size:12px;color:#dc2626;padding:4px 0;border-bottom:1px solid #fef2f2;">⚠ ' + UI.esc(w) + '</div>';
      });
      if (warnings.length > 10) html += '<div style="font-size:11px;color:var(--text-light);margin-top:4px;">+ ' + (warnings.length - 10) + ' more</div>';
      html += '</div>';
    }

    html += '</div>';
    return html;
  },

  // ── Cell Toggle ──
  _toggleCell: function(key) {
    PayrollPage._expandedCells[key] = !PayrollPage._expandedCells[key];
    loadPage('payroll');
  },

  // ── Day Detail Modal ──
  showDayDetail: function(userId, date) {
    var entries = PayrollPage._getEntriesForDate(userId, date);
    var dayName = new Date(date).toLocaleDateString('en-US', { weekday:'long', month:'short', day:'numeric' });

    var html = '<div style="margin-bottom:16px;font-size:14px;color:var(--text-light);">' + dayName + '</div>';

    // Hours list
    if (entries.length === 0) {
      html += '<div style="text-align:center;padding:20px;color:var(--text-light);">No hours recorded</div>';
    } else {
      entries.forEach(function(e, i) {
        html += '<div style="padding:12px;background:var(--bg);border-radius:8px;margin-bottom:8px;">'
          + '<div style="display:flex;justify-content:space-between;align-items:center;">'
          + '<div><strong>' + (e.hours ? e.hours.toFixed(1) + ' hrs' : '—') + '</strong>'
          + (e.clockIn ? '<span style="font-size:12px;color:var(--text-light);margin-left:8px;">' + new Date(e.clockIn).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) + (e.clockOut ? ' – ' + new Date(e.clockOut).toLocaleTimeString([], {hour:'2-digit',minute:'2-digit'}) : ' (no clock-out)') + '</span>' : '')
          + '</div>'
          + '<div style="display:flex;gap:4px;">'
          + '<button onclick="PayrollPage.editHours(\'' + e.id + '\')" class="btn btn-outline" style="font-size:11px;padding:3px 8px;">Edit</button>'
          + '<button onclick="PayrollPage.deleteHours(\'' + e.id + '\',\'' + userId + '\',\'' + date + '\')" class="btn btn-outline" style="font-size:11px;padding:3px 8px;color:var(--red);">×</button>'
          + '</div></div>';
        if (e.jobId) {
          var job = DB.jobs.getById(e.jobId);
          html += '<div style="font-size:11px;color:var(--text-light);margin-top:4px;">Job: ' + (job ? '#' + job.jobNumber + ' ' + (job.clientName || '') : e.jobId) + '</div>';
        }
        if (e.notes) html += '<div style="font-size:12px;color:var(--text-light);margin-top:4px;font-style:italic;">📝 ' + UI.esc(e.notes) + '</div>';
        html += '</div>';
      });
    }

    // Actions
    html += '<div style="display:flex;gap:8px;margin-top:12px;">'
      + '<button onclick="PayrollPage.addHours(\'' + userId + '\',\'' + date + '\')" class="btn btn-primary" style="flex:1;">+ Add Hours</button>'
      + '<button onclick="PayrollPage.addNote(\'' + userId + '\',\'' + date + '\')" class="btn btn-outline" style="flex:1;">📝 Add Note</button>'
      + '</div>';

    // Approval
    var dayKey = PayrollPage._dayApprovalKey(userId, date);
    var dayApproved = PayrollPage._getApprovals()[dayKey] === 'approved';
    html += '<div style="margin-top:12px;text-align:center;">'
      + (dayApproved
        ? '<span style="color:#22c55e;font-weight:700;">✓ Day Approved</span>'
        : '<button onclick="PayrollPage.approveDay(\'' + userId + '\',\'' + date + '\')" class="btn btn-primary" style="width:100%;">✓ Approve Day</button>')
      + '</div>';

    UI.showModal(UI.esc(userId) + ' — ' + dayName, html);
  },

  // ── Add Hours Modal ──
  addHours: function(userId, date) {
    var jobs = DB.jobs.getAll().filter(function(j) { return j.status === 'scheduled' || j.status === 'in_progress' || j.status === 'active'; });
    var opts = '<option value="">— No job —</option>';
    jobs.forEach(function(j) { opts += '<option value="' + j.id + '">#' + (j.jobNumber || '') + ' ' + UI.esc(j.clientName || '') + '</option>'; });

    var html = UI.field('Hours', '<input type="number" id="ph-hours" step="0.25" min="0" max="24" placeholder="8.0">')
      + UI.field('Job', '<select id="ph-job">' + opts + '</select>')
      + UI.field('Clock In', '<input type="time" id="ph-in">')
      + UI.field('Clock Out', '<input type="time" id="ph-out">')
      + UI.field('Notes', '<textarea id="ph-notes" placeholder="Optional notes..."></textarea>');

    UI.showModal('Add Hours — ' + UI.esc(userId), html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="PayrollPage._saveHours(\'' + userId + '\',\'' + date + '\')">Save</button>'
    });
  },

  _saveHours: function(userId, date) {
    var hours = parseFloat(document.getElementById('ph-hours').value) || 0;
    var clockIn = document.getElementById('ph-in').value;
    var clockOut = document.getElementById('ph-out').value;
    if (!hours && !clockIn) { UI.toast('Enter hours or clock in time', 'error'); return; }

    var entry = {
      userId: userId, user: userId, date: date,
      hours: hours,
      jobId: document.getElementById('ph-job').value || null,
      notes: document.getElementById('ph-notes').value || ''
    };

    if (clockIn) {
      entry.clockIn = date + 'T' + clockIn + ':00';
      if (clockOut) {
        entry.clockOut = date + 'T' + clockOut + ':00';
        if (!hours) entry.hours = Math.round(((new Date(entry.clockOut) - new Date(entry.clockIn)) / 3600000) * 100) / 100;
      }
    }

    DB.timeEntries.create(entry);

    // Mark as edited after approval if day was approved
    var dayKey = PayrollPage._dayApprovalKey(userId, date);
    if (PayrollPage._getApprovals()[dayKey] === 'approved') {
      PayrollPage._approvals[dayKey + '_editedAfter'] = true;
      PayrollPage._saveApprovals();
    }

    UI.closeModal();
    UI.toast('Hours added');
    loadPage('payroll');
  },

  editHours: function(entryId) {
    var e = DB.timeEntries.getAll().find(function(t) { return t.id === entryId; });
    if (!e) return;
    var html = UI.field('Hours', '<input type="number" id="eh-hours" step="0.25" value="' + (e.hours || '') + '">')
      + UI.field('Notes', '<textarea id="eh-notes">' + UI.esc(e.notes || '') + '</textarea>');
    UI.showModal('Edit Hours', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="PayrollPage._updateHours(\'' + entryId + '\')">Save</button>'
    });
  },

  _updateHours: function(entryId) {
    DB.timeEntries.update(entryId, {
      hours: parseFloat(document.getElementById('eh-hours').value) || 0,
      notes: document.getElementById('eh-notes').value
    });
    UI.closeModal();
    UI.toast('Hours updated');
    loadPage('payroll');
  },

  deleteHours: function(entryId, userId, date) {
    if (!confirm('Delete these hours?')) return;
    var all = DB.timeEntries.getAll().filter(function(t) { return t.id !== entryId; });
    localStorage.setItem('bm-time-entries', JSON.stringify(all));
    UI.closeModal();
    UI.toast('Hours deleted');
    PayrollPage.showDayDetail(userId, date);
  },

  addNote: function(userId, date) {
    var html = UI.field('Note', '<textarea id="pn-note" placeholder="Add a note for this day..." style="min-height:80px;"></textarea>');
    UI.showModal('Add Note', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Cancel</button>'
        + ' <button class="btn btn-primary" onclick="PayrollPage._saveNote(\'' + userId + '\',\'' + date + '\')">Save</button>'
    });
  },

  _saveNote: function(userId, date) {
    var note = document.getElementById('pn-note').value;
    if (!note.trim()) return;
    DB.timeEntries.create({ userId: userId, user: userId, date: date, hours: 0, notes: note, type: 'note' });
    UI.closeModal();
    UI.toast('Note added');
    loadPage('payroll');
  },

  // ── Approvals ──
  approveDay: function(userId, date) {
    var dayKey = PayrollPage._dayApprovalKey(userId, date);
    PayrollPage._getApprovals();
    PayrollPage._approvals[dayKey] = 'approved';
    delete PayrollPage._approvals[dayKey + '_editedAfter'];
    PayrollPage._saveApprovals();
    UI.closeModal();
    UI.toast('Day approved ✓');
    loadPage('payroll');
  },

  approveEmployee: function(userId, weekStart) {
    var empKey = PayrollPage._approvalKey(userId, weekStart);
    PayrollPage._getApprovals();
    PayrollPage._approvals[empKey] = 'approved';
    PayrollPage._saveApprovals();
    UI.toast(userId + ' approved for the week ✓');
    loadPage('payroll');
  },

  approveAll: function(weekStart) {
    var employees = PayrollPage._getEmployees();
    PayrollPage._getApprovals();
    employees.forEach(function(emp) {
      var empKey = PayrollPage._approvalKey(emp.name || emp.id, weekStart);
      PayrollPage._approvals[empKey] = 'approved';
    });
    PayrollPage._saveApprovals();
    UI.toast('All employees approved ✓');
    loadPage('payroll');
  },

  // ── Payroll Summary Modal ──
  showPayrollSummary: function(weekStart) {
    var dates = PayrollPage._getWeekDates(PayrollPage._weekOffset);
    var employees = PayrollPage._getEmployees();
    var html = '<table class="data-table" style="width:100%;font-size:13px;"><thead><tr><th>Employee</th><th>Regular</th><th>OT</th><th>Total Hrs</th><th>Rate</th><th>Gross Pay</th><th>Status</th></tr></thead><tbody>';

    var grandTotal = 0;
    employees.forEach(function(emp) {
      var weekHours = 0;
      dates.forEach(function(d) {
        weekHours += PayrollPage._totalHours(PayrollPage._getEntriesForDate(emp.name || emp.id, d));
      });
      var regular = Math.min(weekHours, 40);
      var ot = Math.max(0, weekHours - 40);
      var rate = emp.rate || emp.payRate || 0;
      var gross = (regular * rate) + (ot * rate * 1.5);
      grandTotal += gross;
      var empKey = PayrollPage._approvalKey(emp.name || emp.id, weekStart);
      var approved = PayrollPage._getApprovals()[empKey] === 'approved';

      html += '<tr>'
        + '<td style="font-weight:600;">' + UI.esc(emp.name || '') + '</td>'
        + '<td>' + regular.toFixed(1) + '</td>'
        + '<td style="color:' + (ot > 0 ? '#d97706' : 'var(--text)') + ';">' + ot.toFixed(1) + '</td>'
        + '<td style="font-weight:700;">' + weekHours.toFixed(1) + '</td>'
        + '<td>' + (rate ? '$' + rate.toFixed(2) + '/hr' : '—') + '</td>'
        + '<td style="font-weight:700;">' + (rate ? '$' + gross.toFixed(2) : '—') + '</td>'
        + '<td>' + (approved ? '<span style="color:#22c55e;font-weight:600;">✓ Approved</span>' : '<span style="color:#d97706;">Pending</span>') + '</td>'
        + '</tr>';
    });

    html += '<tr style="font-weight:800;border-top:2px solid var(--border);"><td>TOTAL</td><td></td><td></td><td></td><td></td><td>$' + grandTotal.toFixed(2) + '</td><td></td></tr>';
    html += '</tbody></table>';

    UI.showModal('Payroll Summary — Week of ' + new Date(weekStart).toLocaleDateString(), html, { wide: true,
      footer: '<button class="btn btn-outline" onclick="UI.closeModal()">Close</button>'
        + ' <button class="btn btn-primary" onclick="PayrollPage.triggerGusto(\'' + weekStart + '\')">🚀 Send to Gusto</button>'
    });
  },

  // ── Export CSV ──
  exportWeek: function(weekStart) {
    var dates = PayrollPage._getWeekDates(PayrollPage._weekOffset);
    var employees = PayrollPage._getEmployees();
    var rows = ['Employee,Mon,Tue,Wed,Thu,Fri,Sat,Sun,Total,OT,Rate,Gross'];

    employees.forEach(function(emp) {
      var cols = [emp.name];
      var total = 0;
      dates.forEach(function(d) {
        var h = PayrollPage._totalHours(PayrollPage._getEntriesForDate(emp.name || emp.id, d));
        cols.push(h.toFixed(1));
        total += h;
      });
      var ot = Math.max(0, total - 40);
      var rate = emp.rate || emp.payRate || 0;
      var gross = (Math.min(total, 40) * rate) + (ot * rate * 1.5);
      cols.push(total.toFixed(1), ot.toFixed(1), rate.toFixed(2), gross.toFixed(2));
      rows.push(cols.join(','));
    });

    var blob = new Blob([rows.join('\n')], { type: 'text/csv' });
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'payroll-' + weekStart + '.csv';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    UI.toast('Payroll exported');
  },

  // ── Gusto Integration ──
  triggerGusto: function(weekStart) {
    var gustoKey = localStorage.getItem('bm-gusto-api-key');
    if (!gustoKey) {
      UI.showModal('Connect Gusto', '<div style="text-align:center;padding:20px;">'
        + '<div style="font-size:48px;margin-bottom:12px;">💰</div>'
        + '<h3>Connect Gusto for Payroll</h3>'
        + '<p style="color:var(--text-light);margin-bottom:16px;">Enter your Gusto API key to sync employees and submit payroll.</p>'
        + UI.field('Gusto API Key', '<input type="text" id="gusto-key" placeholder="Enter Gusto API key...">')
        + '<button class="btn btn-primary" onclick="localStorage.setItem(\'bm-gusto-api-key\',document.getElementById(\'gusto-key\').value);UI.closeModal();UI.toast(\'Gusto connected!\');loadPage(\'payroll\')">Connect</button>'
        + '</div>');
      return;
    }
    UI.toast('Payroll data sent to Gusto! 🚀');
    // In production: POST to Gusto API with hours data
  }
};

;
/* ──── src/pages/permissions.js ──── */
/**
 * Branch Manager — Enterprise RBAC Permissions System
 * Multi-role support with toggleable permissions per action
 * Roles: Super Admin, Admin, Manager, Employee, Payroll Admin, Accountant, HR Manager, Owner
 * v1
 */
var RBAC = {
  _STORAGE_KEY: 'bm-rbac-roles',

  // Default role definitions with permissions
  _defaultRoles: {
    'super_admin': {
      label: 'Super Admin', color: '#dc2626', icon: '🛡️',
      permissions: { /* all true by default */ }
    },
    'owner': {
      label: 'Owner', color: '#16a34a', icon: '👑',
      permissions: { /* all true by default */ }
    },
    'admin': {
      label: 'Admin', color: '#2563eb', icon: '⚙️',
      permissions: {
        'system.manage_permissions': false,
        'employees.terminate': false
      }
    },
    'manager': {
      label: 'Manager', color: 'var(--accent)', icon: '👷',
      permissions: {
        'system.manage_permissions': false,
        'system.manage_settings': false,
        'employees.terminate': false,
        'employees.change_pay_rates': false,
        'payroll.trigger': false,
        'payroll.fix_errors': false
      }
    },
    'payroll_admin': {
      label: 'Payroll Admin', color: '#ea580c', icon: '💰',
      permissions: {
        'system.manage_permissions': false,
        'system.manage_settings': false,
        'employees.terminate': false,
        'employees.add': false,
        'timesheets.delete_hours': false
      }
    },
    'accountant': {
      label: 'Accountant', color: '#0891b2', icon: '📊',
      permissions: {
        'timesheets.edit_hours': false,
        'timesheets.approve_hours': false,
        'timesheets.delete_hours': false,
        'employees.add': false,
        'employees.terminate': false,
        'employees.assign_roles': false,
        'system.manage_permissions': false,
        'system.manage_settings': false
      }
    },
    'hr_manager': {
      label: 'HR Manager', color: '#be185d', icon: '👥',
      permissions: {
        'payroll.trigger': false,
        'payroll.fix_errors': false,
        'system.manage_permissions': false,
        'system.manage_settings': false
      }
    },
    'employee': {
      label: 'Employee', color: '#6b7280', icon: '🧑‍🔧',
      permissions: {
        'timesheets.edit_hours': false,
        'timesheets.approve_hours': false,
        'timesheets.delete_hours': false,
        'timesheets.view_notes': true,
        'payroll.view_summary': false,
        'payroll.trigger': false,
        'payroll.view_reports': false,
        'payroll.fix_errors': false,
        'payroll.sync_gusto': false,
        'employees.add': false,
        'employees.edit_info': false,
        'employees.change_pay_rates': false,
        'employees.terminate': false,
        'employees.assign_roles': false,
        'system.manage_settings': false,
        'system.manage_permissions': false,
        'system.manage_overtime': false,
        'system.manage_schedules': false,
        'system.manage_job_codes': false,
        'system.manage_notifications': false
      }
    }
  },

  // All available permissions
  _allPermissions: {
    'Timesheets': [
      { key: 'timesheets.view_hours', label: 'View hours' },
      { key: 'timesheets.edit_hours', label: 'Edit hours' },
      { key: 'timesheets.approve_hours', label: 'Approve hours' },
      { key: 'timesheets.delete_hours', label: 'Delete hours' },
      { key: 'timesheets.add_notes', label: 'Add notes' },
      { key: 'timesheets.view_notes', label: 'View notes' },
      { key: 'timesheets.view_photos', label: 'View photos' }
    ],
    'Payroll': [
      { key: 'payroll.view_summary', label: 'View payroll summary' },
      { key: 'payroll.trigger', label: 'Trigger payroll' },
      { key: 'payroll.view_reports', label: 'View payroll reports' },
      { key: 'payroll.fix_errors', label: 'Fix payroll errors' },
      { key: 'payroll.sync_gusto', label: 'Sync with Gusto' },
      { key: 'payroll.view_gusto_status', label: 'View Gusto sync status' }
    ],
    'Employees': [
      { key: 'employees.add', label: 'Add employees' },
      { key: 'employees.edit_info', label: 'Edit employee info' },
      { key: 'employees.change_pay_rates', label: 'Change pay rates' },
      { key: 'employees.terminate', label: 'Terminate employees' },
      { key: 'employees.assign_roles', label: 'Assign roles' },
      { key: 'employees.view_history', label: 'View job history' }
    ],
    'System': [
      { key: 'system.manage_settings', label: 'Manage settings' },
      { key: 'system.manage_notifications', label: 'Manage notifications' },
      { key: 'system.manage_permissions', label: 'Manage permissions' },
      { key: 'system.manage_overtime', label: 'Manage overtime rules' },
      { key: 'system.manage_schedules', label: 'Manage schedules' },
      { key: 'system.manage_job_codes', label: 'Manage job codes' }
    ]
  },

  // Get roles (with custom overrides from localStorage)
  getRoles: function() {
    try {
      var custom = JSON.parse(localStorage.getItem(RBAC._STORAGE_KEY) || '{}');
      var merged = {};
      Object.keys(RBAC._defaultRoles).forEach(function(roleKey) {
        merged[roleKey] = JSON.parse(JSON.stringify(RBAC._defaultRoles[roleKey]));
        if (custom[roleKey] && custom[roleKey].permissions) {
          Object.assign(merged[roleKey].permissions, custom[roleKey].permissions);
        }
      });
      return merged;
    } catch(e) { return JSON.parse(JSON.stringify(RBAC._defaultRoles)); }
  },

  // Check if a role has a specific permission
  can: function(roleKey, permissionKey) {
    var roles = RBAC.getRoles();
    var role = roles[roleKey];
    if (!role) return false;
    if (roleKey === 'super_admin' || roleKey === 'owner') return true;
    if (role.permissions[permissionKey] === false) return false;
    return true; // default to allowed unless explicitly denied
  },

  // Check current user's permission
  currentCan: function(permissionKey) {
    var role = (typeof Auth !== 'undefined' && Auth.role) ? Auth.role : 'owner';
    return RBAC.can(role, permissionKey);
  },

  // Save role permission override
  savePermission: function(roleKey, permKey, value) {
    var custom = {};
    try { custom = JSON.parse(localStorage.getItem(RBAC._STORAGE_KEY) || '{}'); } catch(e) {}
    if (!custom[roleKey]) custom[roleKey] = { permissions: {} };
    custom[roleKey].permissions[permKey] = value;
    localStorage.setItem(RBAC._STORAGE_KEY, JSON.stringify(custom));
  },

  // ── Render Permissions Page ──
  render: function() {
    var roles = RBAC.getRoles();
    var html = '<div style="max-width:900px;">';

    html += '<div class="section-header"><h2>🛡️ Permissions & Roles</h2>'
      + '<p style="color:var(--text-light);margin-top:4px;">Configure what each role can do. Changes apply immediately.</p></div>';

    // Role cards
    html += '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:20px;">';
    Object.keys(roles).forEach(function(key) {
      var r = roles[key];
      html += '<div style="background:var(--white);border:2px solid ' + r.color + '20;border-radius:10px;padding:14px;text-align:center;cursor:pointer;" onclick="RBAC.editRole(\'' + key + '\')">'
        + '<div style="font-size:24px;">' + r.icon + '</div>'
        + '<div style="font-weight:700;font-size:13px;margin-top:4px;">' + r.label + '</div>'
        + '<div style="font-size:11px;color:var(--text-light);margin-top:2px;">' + Object.keys(r.permissions).filter(function(p) { return r.permissions[p] === false; }).length + ' restricted</div>'
        + '</div>';
    });
    html += '</div>';

    // Permission matrix
    html += '<div style="background:var(--white);border:1px solid var(--border);border-radius:12px;overflow:hidden;">';
    Object.keys(RBAC._allPermissions).forEach(function(category) {
      html += '<div style="padding:10px 16px;background:var(--bg);font-size:12px;font-weight:700;color:var(--text-light);text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid var(--border);">' + category + '</div>';
      RBAC._allPermissions[category].forEach(function(perm) {
        html += '<div style="display:flex;align-items:center;padding:8px 16px;border-bottom:1px solid #f5f5f5;gap:8px;">'
          + '<div style="flex:1;font-size:13px;">' + perm.label + '</div>';
        Object.keys(roles).forEach(function(roleKey) {
          var allowed = RBAC.can(roleKey, perm.key);
          html += '<div style="width:60px;text-align:center;font-size:11px;color:' + (allowed ? '#22c55e' : '#ef4444') + ';font-weight:600;">'
            + (roleKey === 'super_admin' || roleKey === 'owner' ? '✓' : (allowed ? '✓' : '✗'))
            + '</div>';
        });
        html += '</div>';
      });
    });
    html += '</div>';

    html += '</div>';
    return html;
  },

  editRole: function(roleKey) {
    var roles = RBAC.getRoles();
    var role = roles[roleKey];
    if (!role) return;
    if (roleKey === 'super_admin' || roleKey === 'owner') {
      UI.toast(role.label + ' has all permissions — cannot be restricted');
      return;
    }

    var html = '<div style="max-height:500px;overflow-y:auto;">';
    Object.keys(RBAC._allPermissions).forEach(function(category) {
      html += '<div style="font-size:12px;font-weight:700;color:var(--text-light);text-transform:uppercase;margin:16px 0 8px;">' + category + '</div>';
      RBAC._allPermissions[category].forEach(function(perm) {
        var allowed = RBAC.can(roleKey, perm.key);
        html += '<label style="display:flex;align-items:center;gap:10px;padding:8px;background:var(--bg);border-radius:6px;margin-bottom:4px;cursor:pointer;">'
          + '<input type="checkbox" ' + (allowed ? 'checked' : '') + ' onchange="RBAC.savePermission(\'' + roleKey + '\',\'' + perm.key + '\',this.checked)">'
          + '<span style="font-size:13px;">' + perm.label + '</span>'
          + '</label>';
      });
    });
    html += '</div>';

    UI.showModal(role.icon + ' ' + role.label + ' Permissions', html, {
      footer: '<button class="btn btn-outline" onclick="UI.closeModal();loadPage(\'permissions\')">Done</button>'
    });
  }
};

;